def app_dir():
    return os.path.dirname(sys.executable if getattr(sys,"frozen",False) else os.path.abspath(__file__))

DB_PATH = os.path.join(app_dir(), "hasat.db")

# ─── VERİTABANI ─────────────────────────────────────────────────────────────
class DB:
    def __init__(self):
        self.conn = sqlite3.connect(DB_PATH, check_same_thread=False)
        self._init()
        self._seed()

    def _init(self):
        c = self.conn.cursor()
        c.executescript("""
            PRAGMA journal_mode=WAL;
            PRAGMA synchronous=NORMAL;
            CREATE TABLE IF NOT EXISTS hasat (tarih TEXT, parsel TEXT, kasa REAL,
                PRIMARY KEY(tarih, parsel));
            CREATE TABLE IF NOT EXISTS ozet (tarih TEXT PRIMARY KEY,
                toplam_kasa REAL DEFAULT 0, personel INTEGER DEFAULT 0);
            CREATE TABLE IF NOT EXISTS ayar (key TEXT PRIMARY KEY, value TEXT);
            CREATE TABLE IF NOT EXISTS form_detay (
                oda TEXT, tarih TEXT, flas INTEGER DEFAULT 1,
                kasa_ikinci REAL DEFAULT 0,
                kok INTEGER DEFAULT 0, renk INTEGER DEFAULT 0,
                tat INTEGER DEFAULT 0, koku INTEGER DEFAULT 0,
                PRIMARY KEY(oda, tarih));
            CREATE TABLE IF NOT EXISTS tarti_detay (
                oda TEXT, tarih TEXT,
                tur INTEGER DEFAULT 1, flas INTEGER DEFAULT 1,
                ana90 REAL DEFAULT 0, kestane REAL DEFAULT 0,
                duble REAL DEFAULT 0, dokme REAL DEFAULT 0, ikinci REAL DEFAULT 0,
                PRIMARY KEY(oda, tarih));
            CREATE INDEX IF NOT EXISTS idx_hasat_tarih ON hasat(tarih);
            CREATE INDEX IF NOT EXISTS idx_hasat_parsel ON hasat(parsel);
            CREATE INDEX IF NOT EXISTS idx_form_oda ON form_detay(oda);
            CREATE TABLE IF NOT EXISTS hasatci_kasa (
                oda TEXT, tarih TEXT, hasatci TEXT, kasa REAL DEFAULT 0,
                PRIMARY KEY(oda, tarih, hasatci));
            CREATE TABLE IF NOT EXISTS kompost_detay (
                oda TEXT, tur INTEGER,
                firma TEXT DEFAULT '', gelis_tarihi TEXT DEFAULT '',
                tonaj REAL DEFAULT 0, alan_m2 REAL DEFAULT 252,
                tur_bitti INTEGER DEFAULT 0,
                PRIMARY KEY(oda, tur));
            CREATE INDEX IF NOT EXISTS idx_tarti_oda ON tarti_detay(oda);
            CREATE INDEX IF NOT EXISTS idx_hasatci ON hasatci_kasa(oda, tarih);
        """)
        self.conn.commit()
        # ── MIGRATION: eski veritabanlarında tur_bitti sütunu yoksa ekle ──
        # (CREATE TABLE IF NOT EXISTS var olan tabloyu değiştirmez, bu yüzden
        # zaten mevcut kompost_detay tabloları için ALTER TABLE gerekir.)
        try:
            kolonlar = [r[1] for r in self.conn.execute("PRAGMA table_info(kompost_detay)").fetchall()]
            if "tur_bitti" not in kolonlar:
                self.conn.execute("ALTER TABLE kompost_detay ADD COLUMN tur_bitti INTEGER DEFAULT 0")
                self.conn.commit()
        except sqlite3.OperationalError:
            pass  # zaten var veya tablo henüz oluşmadıysa sorun değil

    def _seed(self):
        if self.conn.execute("SELECT COUNT(*) FROM hasat").fetchone()[0] > 0:
            return
        if not EMBEDDED:
            return  # Demo verisi yok — boş başla (normal durum)
        try:
            raw = json.loads(base64.b64decode(EMBEDDED).decode())
        except (ValueError, json.JSONDecodeError):
            return  # Gömülü veri bozuksa boş başla
        c = self.conn.cursor()
        gun_toplam = {}  # tarih → toplam kasa (tek geçişte hesapla)
        for ym, pdata in raw.get("harvest", {}).items():
            y, m = ym.split("-")
            for plot, days in pdata.items():
                for ds, kasa in days.items():
                    t = f"{y}-{int(m):02d}-{int(ds):02d}"
                    c.execute("INSERT OR IGNORE INTO hasat VALUES(?,?,?)", (t, plot, kasa))
                    gun_toplam[t] = gun_toplam.get(t, 0) + kasa
        for t, tot in gun_toplam.items():
            c.execute("INSERT OR REPLACE INTO ozet VALUES(?,?,0)", (t, tot))
        self.conn.commit()

    # Günlük kayıt
    def ensure_hasat_row(self, oda, tarih, ana90):
        """hasat tablosunda o oda+tarih için bir satır garantiler — ana90 SIFIR olsa bile.
        Neden gerekli: Sadece Kestane/Duble/Dökme girilip Ana Tartı boş bırakılırsa,
        save_day'in k>0 filtresi o günü hasat tablosuna hiç yazmaz. Bu durumda
        get_oda_gunleri (form, analiz, her şey) o günü GÖREMEZ — veri sessizce kaybolur.
        Bu metod, tarti_detay'da Kestane/Duble/Dökme varsa hasat satırını 0 ile de olsa açar."""
        mevcut = self.conn.execute(
            "SELECT kasa FROM hasat WHERE parsel=? AND tarih=?", (oda, tarih)).fetchone()
        if mevcut is None:
            # Satır hiç yok — aç (ana90 kaç ise o, 0 dahil)
            self.conn.execute("INSERT INTO hasat VALUES(?,?,?)", (tarih, oda, round(ana90, 2)))
            self.conn.commit()

    def save_day(self, tarih, pdict, personel):
        c = self.conn.cursor()
        c.execute("DELETE FROM hasat WHERE tarih=?", (tarih,))
        tot = 0
        for p, k in pdict.items():
            # k>=0 (0 DAHİL): ensure_hasat_row, Ana Tartı boş bırakılıp sadece
            # Kestane/Duble/Dökme girilen günler için kasa=0 satır açar. Eski
            # "k>0" filtresi bu satırları burada (özellikle _tr_hesapla'nın
            # sonundaki personel güncelleme çağrısında) sessizce siliyordu —
            # kestane-only günler Hasat Takip Formu'ndan kayboluyordu.
            if k is not None and k >= 0:
                c.execute("INSERT INTO hasat VALUES(?,?,?)", (tarih, p, k))
                tot += k
        c.execute("INSERT OR REPLACE INTO ozet VALUES(?,?,?)", (tarih, tot, personel))
        self.conn.commit()
        self._backup()
        # tot sadece Ana Tartı(+Direkt) toplamıdır; Kestane/Duble/Dökme dahil
        # gerçek toplamla senkronla (aksi halde ozet.toplam_kasa düşük kalır).
        self.recalc_ozet_toplam(tarih)

    def _backup(self):
        import shutil
        try:
            bak_dir = os.path.join(os.path.dirname(DB_PATH), "yedek")
            os.makedirs(bak_dir, exist_ok=True)
            today = datetime.date.today().strftime("%Y-%m-%d")
            bak = os.path.join(bak_dir, f"hasat_{today}.db")
            if not os.path.exists(bak):
                shutil.copy2(DB_PATH, bak)
                # 30 günden eski yedekleri sil
                for f in os.listdir(bak_dir):
                    fp = os.path.join(bak_dir, f)
                    if os.path.isfile(fp):
                        age = (datetime.date.today() - datetime.date.fromtimestamp(os.path.getmtime(fp))).days
                        if age > 30:
                            os.remove(fp)
        except (OSError, IOError):
            pass  # Yedekleme başarısız olsa da ana işlem devam etsin

    def get_hasat(self, tarih):
        rows = self.conn.execute("SELECT parsel,kasa FROM hasat WHERE tarih=? ORDER BY parsel", (tarih,)).fetchall()
        return {r[0]: r[1] for r in rows}

    def get_kayip_kirilim_gunleri(self):
        """hasat.kasa≈0 ama tarti_detay HİÇ olmayan oda+gün kayıtlarını bulur.
        Bu günlerde Kestane/Duble/Dökme kırılımı kaybolmuştur — toplam kasa
        (ozet tablosunda) korunmuş olsa da hangi kategoriye ne kadar gittiği
        bilinmiyor. Kullanıcı defterinden gerçek değerleri girip düzeltebilir.

        ÖNEMLİ: Döndürülen tutar SADECE O ODAYA ait tahmini kayıp tutardır —
        (o günün ozet.toplam_kasa'sı) EKSİ (o gündeki DİĞER odaların bilinen
        toplamı: hasat.kasa + tarti_detay ekleri). ozet.toplam_kasa'nın kendisini
        kullanmak YANLIŞ olur çünkü o, günün TÜM odalarının toplamıdır.

        Döndürür: [(oda, tarih, tahmini_tur, oda_icin_tahmini_kayip_tutar), ...]"""
        rows = self.conn.execute("""
            SELECT h.parsel, h.tarih
            FROM hasat h
            LEFT JOIN tarti_detay t ON t.oda=h.parsel AND t.tarih=h.tarih
            WHERE t.oda IS NULL AND h.kasa < 1
            ORDER BY h.tarih, h.parsel
        """).fetchall()
        # O günde kaç oda "kayıp" (tarti_detay yok)? Aynı günde birden fazla oda
        # kayıpsa, aşağıdaki tahmini tutar hepsi arasında PAYLAŞTIRILMALI — aksi
        # halde her biri günün TÜM bilinmeyen kısmını kendine mal eder (çifte
        # sayım: 2 oda kayıpsa ikisi de aynı ~tam günü "kendi tutarım" sanır).
        gun_kayip_sayisi = {}
        for oda, tarih in rows:
            gun_kayip_sayisi[tarih] = gun_kayip_sayisi.get(tarih, 0) + 1
        sonuc = []
        for oda, tarih in rows:
            r1 = self.conn.execute(
                "SELECT tur FROM tarti_detay WHERE oda=? AND tarih<=? ORDER BY tarih DESC LIMIT 1",
                (oda, tarih)).fetchone()
            r2 = self.conn.execute(
                "SELECT tur FROM tarti_detay WHERE oda=? AND tarih>=? ORDER BY tarih ASC LIMIT 1",
                (oda, tarih)).fetchone()
            tur = r1[0] if r1 else (r2[0] if r2 else 1)

            # Günün TÜM odalarının toplamı (ozet)
            oz = self.conn.execute(
                "SELECT toplam_kasa FROM ozet WHERE tarih=?", (tarih,)).fetchone()
            gun_tum_odalar = oz[0] if oz else 0

            # O gündeki DİĞER (bu oda hariç) odaların BİLİNEN toplamı
            # (ana90 + kestane + duble + dokme, her oda için tarti_detay varsa ondan,
            #  yoksa hasat.kasa'dan — o oda da kayıpsa 0 sayılır, hesap dışı kalır)
            diger_toplam = 0.0
            for diger_oda, diger_ana90 in self.conn.execute(
                    "SELECT parsel, kasa FROM hasat WHERE tarih=? AND parsel!=?", (tarih, oda)).fetchall():
                dtd = self.conn.execute(
                    "SELECT ana90, kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                    (diger_oda, tarih)).fetchone()
                if dtd:
                    diger_toplam += (dtd[0] or 0) + (dtd[1] or 0) + (dtd[2] or 0) + (dtd[3] or 0)
                else:
                    diger_toplam += (diger_ana90 or 0)  # bu oda da kayıpsa, sadece bilineni say

            oda_icin_tutar = round((gun_tum_odalar - diger_toplam) / gun_kayip_sayisi[tarih], 2)
            sonuc.append((oda, tarih, tur, max(0, oda_icin_tutar)))
        return sonuc

    def duzelt_kayip_kirilim(self, oda, tarih, tur, flas, ana90, kestane, duble, dokme, ikinci):
        """Kayıp bir günün kırılımını elle girilen değerlerle tamamlar.
        tarti_detay'a yazar, hasat.kasa'yı ana90 ile senkronlar, ozet'i günceller."""
        self.set_tarti_detay(oda, tarih, tur, flas, ana90, kestane, duble, dokme, ikinci)
        mevcut = self.conn.execute(
            "SELECT kasa FROM hasat WHERE parsel=? AND tarih=?", (oda, tarih)).fetchone()
        if mevcut is None:
            self.conn.execute("INSERT INTO hasat VALUES(?,?,?)", (tarih, oda, round(ana90, 2)))
        else:
            self.conn.execute("UPDATE hasat SET kasa=? WHERE parsel=? AND tarih=?",
                              (round(ana90, 2), oda, tarih))
        self.conn.commit()
        self.recalc_ozet_toplam(tarih)

    def onarim_onizle(self):
        """Geçmiş kayıtları tara: 
        1) hasat.kasa'nın tarti_detay.ana90'dan FARKLI olduğu satırlar (BİRİNCİ sütunu hatası)
        2) ozet.toplam_kasa'nın gerçek toplamdan (ana90+kestane+duble+dokme) FARKLI olduğu
           günler (Aylık/Yıllık Özet hatası — ozet tablosu güncel değil)
        Değiştirmez, sadece rapor döndürür.
        Döndürür: (sorunlu_kayitlar, toplam_fark, sorunlu_gunler)
          sorunlu_kayitlar: [(oda, tarih, eski_kasa, yeni_ana90, fark), ...]
          sorunlu_gunler: [(tarih, eski_ozet, yeni_ozet, fark), ...]"""
        sorunlu = []
        rows = self.conn.execute("SELECT parsel, tarih, kasa FROM hasat ORDER BY tarih").fetchall()
        for oda, tarih, eski_kasa in rows:
            td = self.conn.execute(
                "SELECT ana90, kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                (oda, tarih)).fetchone()
            if td is None:
                continue  # tarti_detay yok — çok eski veri, dokunma (ayırma imkanı yok)
            ana90, kestane, duble, dokme = (td[0] or 0), (td[1] or 0), (td[2] or 0), (td[3] or 0)
            ekler = kestane + duble + dokme
            if ekler <= 0:
                continue  # ek kategori yok — hasat.kasa zaten sadece ana90 olmalı, sorun olmamalı
            # hasat.kasa, ana90'dan farklıysa (muhtemelen eski toplam formatı) sorunlu say
            if abs((eski_kasa or 0) - ana90) > 0.05:
                fark = round((eski_kasa or 0) - ana90, 2)
                sorunlu.append((oda, tarih, round(eski_kasa or 0, 2), round(ana90, 2), fark))
        toplam_fark = round(sum(s[4] for s in sorunlu), 2)

        # ── ozet.toplam_kasa uyumsuzlukları (Aylık/Yıllık Özet'i etkiler) ──
        sorunlu_gunler = []
        tum_tarihler = set(r[0] for r in self.conn.execute("SELECT DISTINCT tarih FROM hasat").fetchall())
        for tarih in tum_tarihler:
            gercek = 0.0
            for oda, ana90 in self.conn.execute(
                    "SELECT parsel, kasa FROM hasat WHERE tarih=?", (tarih,)).fetchall():
                td = self.get_tarti_detay(oda, tarih)
                gercek += (ana90 or 0) + (td["kestane"] or 0) + (td["duble"] or 0) + (td["dokme"] or 0)
            oz = self.get_ozet(tarih)
            eski_ozet = oz["kasa"] or 0
            if abs(eski_ozet - gercek) > 0.05:
                sorunlu_gunler.append((tarih, round(eski_ozet, 2), round(gercek, 2),
                                       round(eski_ozet - gercek, 2)))
        sorunlu_gunler.sort(key=lambda x: x[0])
        return sorunlu, toplam_fark, sorunlu_gunler

    def onarim_uygula(self, sorunlu_liste, tum_gunleri_de_senkronla=True):
        """onarim_onizle'den gelen listeyi uygular: hasat.kasa'yı tarti_detay.ana90 ile
        değiştirir. Sonra ozet.toplam_kasa'yı senkronlar.

        tum_gunleri_de_senkronla=True (varsayılan): SADECE BİRİNCİ'si düzelen günler değil,
        hasat tablosundaki TÜM günler için ozet.toplam_kasa yeniden hesaplanır. Bu gerekli
        çünkü ozet tablosu, hasat.kasa'dan BAĞIMSIZ olarak eski/yanlış bir değerde
        kalmış olabilir (örn. eski kod sürümlerinden kalma kayıtlar, hiç güncellenmemiş
        günler). Sadece onarım listesindeki günleri senkronlamak yetersiz kalabilir."""
        etkilenen_tarihler = set()
        for oda, tarih, eski_kasa, yeni_ana90, fark in sorunlu_liste:
            self.conn.execute(
                "UPDATE hasat SET kasa=? WHERE parsel=? AND tarih=?",
                (yeni_ana90, oda, tarih))
            etkilenen_tarihler.add(tarih)
        self.conn.commit()

        if tum_gunleri_de_senkronla:
            # hasat tablosundaki TÜM benzersiz tarihleri senkronla (kapsamlı düzeltme)
            tum_tarihler = set(r[0] for r in
                self.conn.execute("SELECT DISTINCT tarih FROM hasat").fetchall())
            duzeltilen_gun_sayisi = 0
            for tarih in tum_tarihler:
                eski_oz = self.get_ozet(tarih)
                yeni_deger = self.recalc_ozet_toplam(tarih)
                if abs((eski_oz["kasa"] or 0) - yeni_deger) > 0.05:
                    duzeltilen_gun_sayisi += 1
            return len(sorunlu_liste), duzeltilen_gun_sayisi
        else:
            for tarih in etkilenen_tarihler:
                self.recalc_ozet_toplam(tarih)
            return len(sorunlu_liste), len(etkilenen_tarihler)

    def recalc_ozet_toplam(self, tarih):
        """ozet.toplam_kasa'yı GERÇEK toplam ile senkronlar: tüm odaların
        Ana Tartı + Kestane + Duble + Dökme toplamı (İkinci hariç).
        hasat tablosu sadece Ana Tartı tutar (BİRİNCİ sütunu doğru kalsın diye),
        ama Günlük/Aylık/Yıllık Özet ekranları gerçek toplamı görmeye devam etsin diye
        bu metod tartı kaydından sonra çağrılır."""
        gercek_toplam = 0.0
        for oda, ana90 in self.conn.execute(
                "SELECT parsel, kasa FROM hasat WHERE tarih=?", (tarih,)).fetchall():
            td = self.get_tarti_detay(oda, tarih)
            gercek_toplam += (ana90 or 0) + (td["kestane"] or 0) + (td["duble"] or 0) + (td["dokme"] or 0)
        oz = self.get_ozet(tarih)
        self.conn.execute("INSERT OR REPLACE INTO ozet VALUES(?,?,?)",
                          (tarih, round(gercek_toplam, 2), oz["personel"]))
        self.conn.commit()
        return round(gercek_toplam, 2)

    def get_ozet(self, tarih):
        r = self.conn.execute("SELECT toplam_kasa,personel FROM ozet WHERE tarih=?", (tarih,)).fetchone()
        return {"kasa": r[0] or 0, "personel": r[1] or 0} if r else {"kasa": 0, "personel": 0}

    def get_daily_in_month(self, y, m):
        """Ay içindeki günlük kasa dağılımı — grafik için"""
        s = f"{y}-{m:02d}-01"
        e = f"{y+1}-01-01" if m == 12 else f"{y}-{m+1:02d}-01"
        rows = self.conn.execute(
            "SELECT tarih, toplam_kasa FROM ozet WHERE tarih>=? AND tarih<? AND toplam_kasa>0 ORDER BY tarih",
            (s, e)).fetchall()
        return [(int(t.split("-")[2]), k) for t, k in rows]  # (gün, kasa)

    def get_tur_ozeti(self, oda, tur, kg_per_kasa=9):
        """TEK KAYNAK: Bir oda+turun özetini Hasat Formu ile BİREBİR aynı şekilde hesaplar.
        Form da, analiz de bu metodu çağırır → her zaman aynı sonuç.

        Form mantığı: hasat tablosundaki günleri (get_oda_gunleri) baz al,
        her gün için tarti_detay'dan satir_toplam = BİRİNCİ + Kestane + Duble + Dökme.
        (İkinci hariç — kullanıcı kuralı.)

        Döndürür: {toplam_kasa, toplam_kg, flas1_kasa, flas2_kasa, gun_sayisi,
                   firma, tonaj, gelis, alan, verim, ilk_hasat_gun, gunler}
        """
        import datetime as _dt
        gunler_ham = self.get_oda_gunleri(oda, tur=tur)  # [(tarih, birinci_kasa), ...]
        toplam = 0.0
        flas_kasa = {1: 0.0, 2: 0.0}
        ilk_hasat = None
        gunler = []
        for tarih, birinci in gunler_ham:
            td = self.get_tarti_detay(oda, tarih)
            # Form ile aynı: satir_toplam = BİRİNCİ + Kestane + Duble + Dökme
            satir = (birinci or 0) + (td["kestane"] or 0) + (td["duble"] or 0) + (td["dokme"] or 0)
            toplam += satir
            f = 2 if td["flas"] == 2 else 1
            flas_kasa[f] += satir
            gunler.append((tarih, satir, f))
            if ilk_hasat is None or tarih < ilk_hasat:
                ilk_hasat = tarih

        # Kompost bilgisi (firma, tonaj, geliş)
        kd = self.get_kompost_detay(oda, tur)
        firma = kd.get("firma", "") or "(belirtilmemiş)"
        tonaj = kd.get("tonaj", 0) or 0
        gelis = kd.get("gelis", "")
        alan = kd.get("alan", 252) or 252

        toplam_kg = toplam * kg_per_kasa
        verim = (toplam_kg / tonaj * 100) if tonaj > 0 else None

        # Kompost → ilk hasat gün farkı
        ilk_hasat_gun = None
        if gelis and ilk_hasat:
            try:
                g = _dt.datetime.strptime(gelis, "%d.%m.%Y").date()
            except ValueError:
                try:
                    g = _dt.datetime.strptime(gelis, "%Y-%m-%d").date()
                except ValueError:
                    g = None
            try:
                ih = _dt.datetime.strptime(ilk_hasat, "%Y-%m-%d").date()
            except ValueError:
                ih = None
            if g and ih:
                ilk_hasat_gun = (ih - g).days

        return {
            "oda": oda, "tur": tur,
            "toplam_kasa": round(toplam, 2),
            "toplam_kg": round(toplam_kg, 2),
            "flas1_kasa": round(flas_kasa[1], 2),
            "flas2_kasa": round(flas_kasa[2], 2),
            "gun_sayisi": len(gunler),
            "firma": firma, "tonaj": tonaj, "gelis": gelis, "alan": alan,
            "verim": round(verim, 2) if verim is not None else None,
            "ilk_hasat_gun": ilk_hasat_gun,
            "gunler": gunler,
            "tur_bitti": kd.get("tur_bitti", False),
        }

    def get_oda_gunleri(self, oda, tur=None):
        """Bir odanın tartıdan gelen günlerini döndür. tur verilirse sadece o tur.
        NOT: kasa>0 filtresi YOK — çünkü Ana Tartı(ana90) sıfır olsa bile o gün
        sadece Kestane/Duble/Dökme girilmiş olabilir (ensure_hasat_row bu günleri
        0 ile de olsa hasat tablosuna yazar). Filtre olsaydı bu günler kaybolurdu."""
        rows = self.conn.execute(
            "SELECT tarih, kasa FROM hasat WHERE parsel=? ORDER BY tarih",
            (oda,)).fetchall()
        sonuc = []
        for t, k in rows:
            if tur is not None:
                td = self.get_tarti_detay(oda, t)
                if td["tur"] != tur:
                    continue
            sonuc.append((t, k))
        return sonuc

    def otomatik_tur_flas(self, oda, son_tur, bosluk_gun=30, flas1_gun=5):
        """Boşluklara göre dönemleri ayırıp tur/flaş atar.
        son_tur: bu odanın EN SON döneminin tur numarası.
        Geriye doğru sayarak tüm dönemleri numaralar.
        Her dönemin ilk flas1_gun günü Flaş 1, kalanı Flaş 2."""
        import datetime as _dt
        # kasa>0 filtresi YOK: ana90=0 ama ensure_hasat_row ile açılmış,
        # gerçek Kestane/Duble/Dökme verisi taşıyan günler de dönemlere
        # dahil edilmeli (aksi halde tur/flaş boşluk tespitinde görünmez kalır).
        rows = self.conn.execute(
            "SELECT tarih, kasa FROM hasat WHERE parsel=? ORDER BY tarih",
            (oda,)).fetchall()
        if not rows:
            return 0
        gunler = []
        for t, k in rows:
            try:
                d = _dt.datetime.strptime(t, "%Y-%m-%d").date()
                gunler.append((t, d))
            except ValueError:
                continue
        # Dönemlere böl
        donemler = [[gunler[0]]]
        for i in range(1, len(gunler)):
            if (gunler[i][1] - gunler[i-1][1]).days >= bosluk_gun:
                donemler.append([gunler[i]])
            else:
                donemler[-1].append(gunler[i])
        # Tur numaraları: son dönem = son_tur, geriye say
        ilk_tur = son_tur - len(donemler) + 1
        atanan = 0
        for j, donem in enumerate(donemler):
            tur = ilk_tur + j
            for k, (tarih, d) in enumerate(donem):
                flas = 1 if k < flas1_gun else 2
                # Mevcut kategori verisini koru
                td = self.get_tarti_detay(oda, tarih)
                ana90 = td["ana90"]
                if ana90 == 0 and td["kestane"]==0 and td["duble"]==0 and td["dokme"]==0:
                    # Eski veri — toplam kasayı ana90'a koru
                    kasa = self.conn.execute(
                        "SELECT kasa FROM hasat WHERE parsel=? AND tarih=?",
                        (oda, tarih)).fetchone()
                    ana90 = kasa[0] if kasa else 0
                self.set_tarti_detay(oda, tarih, tur, flas,
                    ana90, td["kestane"], td["duble"], td["dokme"], td["ikinci"])
                atanan += 1
        return atanan, len(donemler), ilk_tur

    def oda_kaydi_sil(self, oda, tarih):
        """Belirli bir gün+odanın TÜM kayıtlarını siler (tüm tablolardan).
        Diğer odalar ve günün özeti korunur/yeniden hesaplanır."""
        c = self.conn.cursor()
        # 1. Bu oda+gün kayıtlarını sil
        c.execute("DELETE FROM hasat WHERE tarih=? AND parsel=?", (tarih, oda))
        c.execute("DELETE FROM tarti_detay WHERE oda=? AND tarih=?", (oda, tarih))
        c.execute("DELETE FROM hasatci_kasa WHERE oda=? AND tarih=?", (oda, tarih))
        c.execute("DELETE FROM form_detay WHERE oda=? AND tarih=?", (oda, tarih))
        # 2. Günün özetini yeniden hesapla (kalan odalar, Kestane/Duble/Dökme dahil)
        kalan = 0.0
        for r_oda, r_kasa in c.execute(
                "SELECT parsel, kasa FROM hasat WHERE tarih=?", (tarih,)).fetchall():
            r_td = c.execute(
                "SELECT kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                (r_oda, tarih)).fetchone()
            kalan += (r_kasa or 0) + ((r_td[0] or 0) + (r_td[1] or 0) + (r_td[2] or 0) if r_td else 0)
        kalan = round(kalan, 2)
        # Personel = kalan günün benzersiz hasatçısı
        kisiler = set()
        for (hh,) in c.execute(
                "SELECT DISTINCT hasatci FROM hasatci_kasa WHERE tarih=? AND kasa>0", (tarih,)).fetchall():
            kisiler.add(hh)
        if kalan > 0:
            c.execute("INSERT OR REPLACE INTO ozet VALUES(?,?,?)", (tarih, kalan, len(kisiler)))
        else:
            # Günde başka oda kalmadıysa özeti de sil
            c.execute("DELETE FROM ozet WHERE tarih=?", (tarih,))
        self.conn.commit()
        # Üretim Takip (web) ile canlı senkron — silinen oda+tarih kaydını
        # Firestore'dan da kaldır (aksi halde web'de "hayalet" kayıt kalır).
        # Yerel silmeyi ASLA etkilemez/engellemez (bkz. firestore_sync.py).
        if HAS_SYNC:
            try:
                firestore_sync.enqueue_hasat_delete(oda, tarih)
            except Exception:
                pass  # senkron asla yerel silmeyi bozmasın

    def oda_kaydi_kasa_guncelle(self, oda, tarih, yeni_kasa, yeni_hasatcilar=None):
        """Bir gün+odanın kasa toplamını günceller. yeni_hasatcilar verilirse
        o liste kullanılır (kim çalıştı değiştirilir); verilmezse mevcut hasatçılar korunur.
        Hasatçılar yeni kasaya göre eşit dağıtılır. Özet de güncellenir."""
        c = self.conn.cursor()
        # 1. hasat tablosundaki kasayı güncelle
        c.execute("INSERT OR REPLACE INTO hasat VALUES(?,?,?)", (tarih, oda, yeni_kasa))
        # 2. tarti_detay varsa ana90'ı yeni kasaya çek (kategori kırılımı sıfırlanır,
        #    çünkü düzeltme genelde toplam kasayı düzeltmek için yapılır)
        td = self.conn.execute(
            "SELECT tur, flas FROM tarti_detay WHERE oda=? AND tarih=?", (oda, tarih)).fetchone()
        if td:
            tur, flas = td
            c.execute("INSERT OR REPLACE INTO tarti_detay VALUES(?,?,?,?,?,?,?,?,?)",
                      (oda, tarih, tur, flas, yeni_kasa, 0, 0, 0, 0))
        # 3. Hasatçı listesi: yeni verilen varsa onu kullan, yoksa mevcudu koru
        if yeni_hasatcilar is not None:
            hasatcilar = list(yeni_hasatcilar)
        else:
            hasatcilar = [r[0] for r in c.execute(
                "SELECT hasatci FROM hasatci_kasa WHERE oda=? AND tarih=? AND kasa>0",
                (oda, tarih)).fetchall()]
        c.execute("DELETE FROM hasatci_kasa WHERE oda=? AND tarih=?", (oda, tarih))
        if hasatcilar:
            kisi_basi = round(yeni_kasa / len(hasatcilar), 2)
            for h in hasatcilar:
                c.execute("INSERT INTO hasatci_kasa VALUES(?,?,?,?)", (oda, tarih, h, kisi_basi))
        # 4. Günün özetini yeniden hesapla (Kestane/Duble/Dökme dahil)
        gun_toplam = 0.0
        for r_oda, r_kasa in c.execute(
                "SELECT parsel, kasa FROM hasat WHERE tarih=?", (tarih,)).fetchall():
            r_td = c.execute(
                "SELECT kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                (r_oda, tarih)).fetchone()
            gun_toplam += (r_kasa or 0) + ((r_td[0] or 0) + (r_td[1] or 0) + (r_td[2] or 0) if r_td else 0)
        gun_toplam = round(gun_toplam, 2)
        kisiler = set()
        for (hh,) in c.execute(
                "SELECT DISTINCT hasatci FROM hasatci_kasa WHERE tarih=? AND kasa>0", (tarih,)).fetchall():
            kisiler.add(hh)
        c.execute("INSERT OR REPLACE INTO ozet VALUES(?,?,?)", (tarih, gun_toplam, len(kisiler)))
        self.conn.commit()
        # Üretim Takip (web) ile canlı senkron — düzeltilen kasa değerini web'e de
        # yansıt (bu yol set_tarti_detay'ı atladığı için ayrıca çağrılır). tur/flas
        # biliniyorsa gönder; kategoriler bu düzeltmede sıfırlandığı için 0.
        if HAS_SYNC and td:
            try:
                kd = self.get_kompost_detay(oda, tur)
                firestore_sync.enqueue_hasat_sync(
                    oda, tarih, tur, flas, yeni_kasa, 0, 0, 0, 0,
                    gelis_tarihi=kd.get("gelis", ""),
                    firma=kd.get("firma", ""), tonaj=kd.get("tonaj", 0))
            except Exception:
                pass  # senkron asla yerel güncellemeyi bozmasın

    def get_tiksiz_gunler(self, baslangic, bitis):
        """Belirtilen tarih aralığında HASATÇI İŞARETİ OLMAYAN günleri döndürür.
        Yani hasat var ama o gün kimin çalıştığı (hasatci_kasa) girilmemiş günler.
        Bu günlerde personel toplu girilebilir. Tiki olan günler LİSTEYE ALINMAZ.
        Döndürür: [(tarih, toplam_kasa, oda_sayisi, mevcut_personel), ...]

        NOT: toplam_kasa artık ozet.toplam_kasa'dan okunur — Günlük Özet ekranıyla
        AYNI kaynak. Önceden hasat.kasa (sadece Ana Tartı) kullanılıyordu, bu da
        Kestane/Duble/Dökme'yi dışlayıp Günlük Özet'ten FARKLI bir rakam gösteriyordu."""
        sonuc = []
        # Aralıktaki hasat olan günler (benzersiz tarih). kasa>0 filtresi YOK —
        # ana90=0 olsa bile Kestane/Duble girilmiş günler de listelensin.
        gunler = self.conn.execute(
            "SELECT tarih, COUNT(*) FROM hasat "
            "WHERE tarih BETWEEN ? AND ? GROUP BY tarih ORDER BY tarih",
            (baslangic, bitis)).fetchall()
        for tarih, oda_sayisi in gunler:
            # Bu günde hasatçı tiki var mı?
            tik_sayisi = self.conn.execute(
                "SELECT COUNT(*) FROM hasatci_kasa WHERE tarih=? AND kasa>0",
                (tarih,)).fetchone()[0]
            if tik_sayisi > 0:
                continue  # tiki var — listeye ALMA (yanlışlıkla bozulmasın)
            # Toplam kasa: ozet.toplam_kasa (Günlük Özet ile AYNI kaynak, Kestane/Duble/Dökme dahil)
            oz = self.conn.execute(
                "SELECT toplam_kasa, personel FROM ozet WHERE tarih=?", (tarih,)).fetchone()
            toplam_kasa = oz[0] if oz else 0
            mevcut = oz[1] if oz else 0
            if not toplam_kasa or toplam_kasa <= 0:
                continue  # gerçek üretim yoksa (sadece 0'lık kayıt) listeleme
            sonuc.append((tarih, round(toplam_kasa or 0, 2), oda_sayisi, mevcut or 0))
        return sonuc

    def toplu_personel_yaz(self, personel_map):
        """personel_map: {tarih: personel_sayisi}. Sadece ozet tablosundaki personel
        alanını günceller (toplam_kasa'ya dokunmaz). Kişi başı hesabı bu personeli kullanır."""
        c = self.conn.cursor()
        yazilan = 0
        for tarih, personel in personel_map.items():
            if personel is None or personel <= 0:
                continue
            # Güvenlik: bu günde gerçekten hasatçı tiki YOK mu? (varsa atla)
            tik = c.execute("SELECT COUNT(*) FROM hasatci_kasa WHERE tarih=? AND kasa>0",
                            (tarih,)).fetchone()[0]
            if tik > 0:
                continue
            # Günün toplam kasasını koru (dokunma), sadece personeli yaz
            oz_row = c.execute("SELECT toplam_kasa FROM ozet WHERE tarih=?",
                               (tarih,)).fetchone()
            gun_kasa = (oz_row[0] if oz_row else 0) or 0
            c.execute("INSERT OR REPLACE INTO ozet VALUES(?,?,?)",
                      (tarih, gun_kasa, int(personel)))
            yazilan += 1
        self.conn.commit()
        return yazilan

    def get_hasatci_kasa(self, oda, tarih):
        """O gün o odada çalışan hasatçılar ve kasaları → {hasatci: kasa}"""
        rows = self.conn.execute(
            "SELECT hasatci, kasa FROM hasatci_kasa WHERE oda=? AND tarih=? ORDER BY hasatci",
            (oda, tarih)).fetchall()
        return {h: k for h, k in rows}

    def set_hasatci_kasa(self, oda, tarih, dagilim):
        """dagilim: {hasatci: kasa}. O gün+oda için tüm hasatçı kayıtlarını yeniler."""
        self.conn.execute("DELETE FROM hasatci_kasa WHERE oda=? AND tarih=?", (oda, tarih))
        for h, k in dagilim.items():
            if k and k > 0:
                self.conn.execute(
                    "INSERT OR REPLACE INTO hasatci_kasa VALUES(?,?,?,?)", (oda, tarih, h, k))
        self.conn.commit()

    def add_hasatci_kasa(self, oda, tarih, dagilim):
        """dagilim: {hasatci: eklenecek_kasa}. Mevcut kaydı SİLMEZ, üstüne EKLER.
        Aynı gün+oda için birden fazla tartı oturumu olabilir; her oturum
        kendi payını önceki oturumların üstüne eklemeli (set_hasatci_kasa'nın
        aksine — o TÜM günü yeniden dağıtır ve önceki oturumları siler)."""
        for h, k in dagilim.items():
            if not k or k <= 0:
                continue
            mevcut = self.conn.execute(
                "SELECT kasa FROM hasatci_kasa WHERE oda=? AND tarih=? AND hasatci=?",
                (oda, tarih, h)).fetchone()
            yeni = round((mevcut[0] if mevcut else 0) + k, 2)
            self.conn.execute(
                "INSERT OR REPLACE INTO hasatci_kasa VALUES(?,?,?,?)", (oda, tarih, h, yeni))
        self.conn.commit()

    def butunluk_kontrol(self):
        """4 tablo arası tutarsızlıkları tespit eder. Liste döndürür: [(tip, açıklama, oda, tarih), ...]"""
        sorunlar = []
        # 1. hasat.kasa artık SADECE Ana Tartı/90 tutar (Kestane/Duble/Dökme hariç) — bu NORMAL.
        # Doğru kontrol: hasat.kasa, tarti_detay.ana90 ile eşit olmalı (ikisi de "sadece ana90").
        rows = self.conn.execute(
            "SELECT parsel, tarih, kasa FROM hasat WHERE kasa>0").fetchall()
        for oda, tarih, kasa in rows:
            td = self.conn.execute(
                "SELECT ana90, kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                (oda, tarih)).fetchone()
            if td:
                ana90_detay = td[0] or 0
                if abs(ana90_detay - kasa) > 0.5:
                    sorunlar.append(("toplam_uyumsuz",
                        f"hasat.kasa {fmt(kasa)} ama tarti_detay.ana90 {fmt(ana90_detay)} "
                        f"(fark {fmt(abs(ana90_detay-kasa))}) — ikisi eşit olmalı",
                        oda, tarih))
            # tarti_detay yoksa bu eski veri — sorun değil, sadece bilgi
        # 2. tarti_detay'da olup hasat'ta olmayan (öksüz detay)
        td_rows = self.conn.execute("SELECT oda, tarih FROM tarti_detay").fetchall()
        for oda, tarih in td_rows:
            h = self.conn.execute(
                "SELECT kasa FROM hasat WHERE parsel=? AND tarih=?", (oda, tarih)).fetchone()
            # NOT: hasat.kasa=0 olması ANORMAL değil — ensure_hasat_row bilerek
            # 0-kasa satır açar (Ana Tartı boş, sadece Kestane/Duble/Dökme girilen
            # günler). Gerçekten öksüz olan tek durum: hasat satırı HİÇ yok (h None).
            if h is None:
                sorunlar.append(("oksuz_detay",
                    "Tartı detayı var ama hasat kaydı hiç yok", oda, tarih))
        # 3. hasatci_kasa toplamı ≠ günün GERÇEK toplamı (ana90+kestane+duble+dokme)
        hk_gunler = self.conn.execute(
            "SELECT DISTINCT oda, tarih FROM hasatci_kasa").fetchall()
        for oda, tarih in hk_gunler:
            hk_top = self.conn.execute(
                "SELECT SUM(kasa) FROM hasatci_kasa WHERE oda=? AND tarih=?",
                (oda, tarih)).fetchone()[0] or 0
            h = self.conn.execute(
                "SELECT kasa FROM hasat WHERE parsel=? AND tarih=?", (oda, tarih)).fetchone()
            td_g = self.conn.execute(
                "SELECT kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                (oda, tarih)).fetchone()
            gun_top = (h[0] if h else 0) or 0
            if td_g:
                gun_top += (td_g[0] or 0) + (td_g[1] or 0) + (td_g[2] or 0)
            if abs(hk_top - gun_top) > 0.5:
                sorunlar.append(("hasatci_uyumsuz",
                    f"Hasatçı toplamı {fmt(hk_top)} ama gün toplamı {fmt(gun_top)}",
                    oda, tarih))
        # 4. form_detay / hasatci_kasa'da olup artık hasat'ta olmayan güne ait kayıt
        for tablo in ("form_detay", "hasatci_kasa"):
            kayitlar = self.conn.execute(
                f"SELECT DISTINCT oda, tarih FROM {tablo}").fetchall()
            for oda, tarih in kayitlar:
                h = self.conn.execute(
                    "SELECT kasa FROM hasat WHERE parsel=? AND tarih=?", (oda, tarih)).fetchone()
                # hasat.kasa=0 meşru olabilir (kestane/duble/dökme-only gün) —
                # sadece hasat satırı hiç yoksa gerçekten öksüz say.
                if h is None:
                    sorunlar.append(("oksuz_kayit",
                        f"{tablo} kaydı var ama hasat yok", oda, tarih))
        return sorunlar

    def butunluk_onar(self, sorunlar):
        """Tespit edilen sorunları onarır. Onarılan sayısını döndürür."""
        onarilan = 0
        for tip, aciklama, oda, tarih in sorunlar:
            if tip == "toplam_uyumsuz":
                # hasat toplamını tarti_detay'a göre düzelt (detay daha kırılımlı, doğru kabul)
                td = self.conn.execute(
                    "SELECT ana90, kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                    (oda, tarih)).fetchone()
                if td:
                    yeni = round((td[0] or 0)+(td[1] or 0)+(td[2] or 0)+(td[3] or 0), 2)
                    self.conn.execute("UPDATE hasat SET kasa=? WHERE parsel=? AND tarih=?",
                                      (yeni, oda, tarih))
                    onarilan += 1
            elif tip == "oksuz_detay":
                # Hasat satırı GERÇEKTEN yoksa (butunluk_kontrol artık bunu h is None
                # ile tespit ediyor) — tarti_detay'daki veriyi SİLMEK yerine, eksik
                # hasat satırını tarti_detay.ana90'dan yeniden oluştur (ensure_hasat_row
                # ile aynı mantık). Eski davranış (tarti_detay'ı silmek) Kestane/Duble/
                # Dökme-only günlerin verisini kalıcı olarak yok ediyordu.
                td = self.conn.execute(
                    "SELECT ana90 FROM tarti_detay WHERE oda=? AND tarih=?", (oda, tarih)).fetchone()
                ana90 = round((td[0] or 0) if td else 0, 2)
                self.conn.execute("INSERT INTO hasat VALUES(?,?,?)", (tarih, oda, ana90))
                self.recalc_ozet_toplam(tarih)
                onarilan += 1
            elif tip == "oksuz_kayit":
                # form_detay ve hasatci_kasa öksüz kayıtlarını sil
                self.conn.execute("DELETE FROM form_detay WHERE oda=? AND tarih=?", (oda, tarih))
                self.conn.execute("DELETE FROM hasatci_kasa WHERE oda=? AND tarih=?", (oda, tarih))
                onarilan += 1
            elif tip == "hasatci_uyumsuz":
                # Hasatçı kasalarını günün GERÇEK toplamına göre eşit yeniden dağıt
                kisiler = self.conn.execute(
                    "SELECT hasatci FROM hasatci_kasa WHERE oda=? AND tarih=?",
                    (oda, tarih)).fetchall()
                h = self.conn.execute(
                    "SELECT kasa FROM hasat WHERE parsel=? AND tarih=?", (oda, tarih)).fetchone()
                td_g = self.conn.execute(
                    "SELECT kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                    (oda, tarih)).fetchone()
                gun_top = (h[0] if h else 0) or 0
                if td_g:
                    gun_top += (td_g[0] or 0) + (td_g[1] or 0) + (td_g[2] or 0)
                if kisiler and gun_top > 0:
                    pay = round(gun_top / len(kisiler), 2)
                    for (k,) in kisiler:
                        self.conn.execute(
                            "UPDATE hasatci_kasa SET kasa=? WHERE oda=? AND tarih=? AND hasatci=?",
                            (pay, oda, tarih, k))
                    onarilan += 1
        self.conn.commit()
        return onarilan

    def get_kompost_analiz(self, kg_per_kasa=9):
        """Kompost firması + tur bazlı verim analizi (tüm zamanlar).
        Her oda+tur için: toplam hasat (kasa/kg), kompost firması/tonaj,
        verim %, kompost→ilk hasat gün farkı.
        Döndürür: {
          'firma_verim': {firma: {tur_sayisi, ort_verim, toplam_kasa, ...}},
          'firma_sure': {firma: ort_kompost_hasat_gun},
          'tur_verim': {oda: [{tur, verim, kasa}, ...]},  # turun yaşlanması
          'detaylar': [{oda, tur, firma, kasa, kg, tonaj, verim, ilk_hasat_gun}, ...]
        }"""
        import datetime as _dt
        # ── TEK KAYNAK: Her oda+tur için get_tur_ozeti (Hasat Formu ile birebir aynı) ──
        # Önce hangi oda+tur kombinasyonları var, onları bul
        oda_tur_set = set()
        # tarti_detay'da kayıtlı oda+turlar (hasat.kasa=0 olsa bile — Kestane/Duble
        # tek başına girilmiş olabilir, ana90 sıfır diye o gün dışlanmamalı)
        for oda, tur in self.conn.execute(
                "SELECT DISTINCT t.oda, t.tur FROM tarti_detay t "
                "JOIN hasat h ON h.parsel=t.oda AND h.tarih=t.tarih"):
            oda_tur_set.add((oda, tur))

        detaylar = []
        firma_kayit = {}   # firma → [(verim, kasa), ...]
        firma_sure = {}    # firma → [gün, ...]
        tur_verim = {}     # oda → [(tur, verim, kasa), ...]

        for oda, tur in oda_tur_set:
            # TEK KAYNAK — form ile birebir aynı hesap
            ozet = self.get_tur_ozeti(oda, tur, kg_per_kasa)
            kasa = ozet["toplam_kasa"]
            if kasa <= 0:
                continue
            firma = ozet["firma"]
            tonaj = ozet["tonaj"]
            kg = ozet["toplam_kg"]
            verim = ozet["verim"]
            ilk_hasat_gun = ozet["ilk_hasat_gun"]
            tur_bitti = ozet["tur_bitti"]

            detaylar.append({
                "oda": oda, "tur": tur, "firma": firma,
                "kasa": round(kasa, 2), "kg": round(kg, 2),
                "tonaj": tonaj, "verim": verim,
                "ilk_hasat_gun": ilk_hasat_gun,
                "tur_bitti": tur_bitti,
            })
            # Firma ortalaması ve süre hesabına SADECE BİTMİŞ turlar girsin.
            # Devam eden bir tur henüz tüm hasadını vermediği için verimi
            # yapay olarak düşük çıkar — ortalamayı bozar.
            if verim is not None and tur_bitti:
                firma_kayit.setdefault(firma, []).append((verim, kasa))
                tur_verim.setdefault(oda, []).append((tur, verim, round(kasa, 2)))
            if ilk_hasat_gun is not None and 0 <= ilk_hasat_gun <= 120 and tur_bitti:
                firma_sure.setdefault(firma, []).append(ilk_hasat_gun)

        # Firma verim özeti
        import statistics as _st
        firma_verim = {}
        for firma, kayitlar in firma_kayit.items():
            verimler = [v for v, k in kayitlar]
            kasalar = [k for v, k in kayitlar]
            firma_verim[firma] = {
                "tur_sayisi": len(kayitlar),
                "ort_verim": round(_st.mean(verimler), 2),
                "toplam_kasa": round(sum(kasalar), 2),
            }
        # Firma süre özeti
        firma_sure_ort = {f: round(_st.mean(g), 1) for f, g in firma_sure.items() if g}
        # Tur verim sıralı (oda içinde tura göre)
        for oda in tur_verim:
            tur_verim[oda].sort(key=lambda x: x[0])

        return {
            "firma_verim": firma_verim,
            "firma_sure": firma_sure_ort,
            "tur_verim": tur_verim,
            "detaylar": detaylar,
        }

    def get_donem_metrik(self, yil, ay, kg_per_kasa=9):
        """Bir ayın operasyonel metrikleri — Analiz sekmesi için.
        Gerçek şema: hasat (toplam kasa) + tarti_detay (flaş/kategori) + hasatci_kasa (kişi).
        Döndürür: toplam_kasa, toplam_kg, adam_gun, çalışılan gün, kişi başı verim,
                  flaş kırılımı, oda kırılımı."""
        import calendar as _cal
        son_gun = _cal.monthrange(yil, ay)[1]
        ilk = f"{yil:04d}-{ay:02d}-01"
        son = f"{yil:04d}-{ay:02d}-{son_gun:02d}"

        # Toplam kasa + oda kırılımı — her gün için tarti_detay'dan satir_toplam
        # (ana90+kestane+duble+dökme). hasat tablosu sadece ana90 tutar, bu yüzden
        # Kestane/Duble'yi tarti_detay'dan eklemek gerekir (Hasat Formu ile tutarlı).
        oda_kasa = {}
        toplam_kasa = 0
        gun_kasa = {}
        for oda, tarih_h, kasa_h in self.conn.execute(
                "SELECT parsel, tarih, kasa FROM hasat WHERE tarih BETWEEN ? AND ?",
                (ilk, son)).fetchall():
            td = self.conn.execute(
                "SELECT ana90, kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                (oda, tarih_h)).fetchone()
            if td:
                satir = (td[0] or 0) + (td[1] or 0) + (td[2] or 0) + (td[3] or 0)
                if satir == 0 and kasa_h:
                    satir = kasa_h
            else:
                satir = kasa_h or 0
            oda_kasa[oda] = round(oda_kasa.get(oda, 0) + satir, 2)
            toplam_kasa += satir
            gun_kasa[tarih_h] = round(gun_kasa.get(tarih_h, 0) + satir, 2)

        # Flaş kırılımı — hasat tablosundaki günleri baz al (toplam_kasa ile tutarlı),
        # her gün için tarti_detay'dan satir_toplam ve flaş bilgisi
        flas_kasa = {1: 0.0, 2: 0.0}
        for oda_p, tarih_h, kasa_h in self.conn.execute(
                "SELECT parsel, tarih, kasa FROM hasat WHERE tarih BETWEEN ? AND ?",
                (ilk, son)).fetchall():
            td = self.conn.execute(
                "SELECT flas, ana90, kestane, duble, dokme FROM tarti_detay WHERE oda=? AND tarih=?",
                (oda_p, tarih_h)).fetchone()
            if td:
                flas, a90, kes, dub, dok = td
                satir = (a90 or 0) + (kes or 0) + (dub or 0) + (dok or 0)
                if satir == 0 and kasa_h:
                    satir = kasa_h
                f = 2 if flas == 2 else 1
            else:
                # tarti_detay yok — flaş 1 varsay, hasat kasasını kullan
                satir = kasa_h or 0
                f = 1
            flas_kasa[f] += satir

        # Adam-gün: her gün çalışan personel sayısının toplamı.
        # ozet.personel EN DOĞRU kaynak — kaydetmede tik+ekstra oraya yazılır.
        # Sadece ozet'te hiç personel yoksa tiklerden say (güvenlik).
        gun_kisi = {}  # tarih → set(hasatçı) — tikli günler (yedek için)
        for tarih, hasatci in self.conn.execute(
                "SELECT DISTINCT tarih, hasatci FROM hasatci_kasa WHERE tarih BETWEEN ? AND ? AND kasa>0",
                (ilk, son)).fetchall():
            gun_kisi.setdefault(tarih, set()).add(hasatci)
        gun_personel = {}      # tarih → kişi sayısı
        for tarih, pers in self.conn.execute(
                "SELECT tarih, personel FROM ozet WHERE tarih BETWEEN ? AND ? AND toplam_kasa>0",
                (ilk, son)).fetchall():
            if pers and pers > 0:
                # ozet'teki personel (tik + ekstra, veya toplu girilen) — asıl kaynak
                gun_personel[tarih] = pers
            elif tarih in gun_kisi:
                # ozet'te personel 0 ama tik var → tiklerden say
                gun_personel[tarih] = len(gun_kisi[tarih])
        # ozet'te hiç olmayan ama tikli günler
        for tarih, kisiler in gun_kisi.items():
            if tarih not in gun_personel:
                gun_personel[tarih] = len(kisiler)

        adam_gun = sum(gun_personel.values())
        calisilan_gun = len(gun_personel)

        # gun_kasa (ay içi trend + rekor gün için) yukarıdaki döngüde, toplam_kasa
        # ile AYNI satir (ana90+kestane+duble+dökme) değerlerinden biriktirildi —
        # eskiden ayrı bir sorguyla sadece hasat.kasa (ana90-only) toplanıyordu ve
        # bu, aynı ekrandaki toplam_kasa ile tutarsız "Rekor Gün" sonucu veriyordu.

        toplam_kg = toplam_kasa * kg_per_kasa
        return {
            "yil": yil, "ay": ay,
            "toplam_kasa": round(toplam_kasa, 2),
            "toplam_kg": round(toplam_kg, 2),
            "oda_kasa": oda_kasa,
            "flas_kasa": {k: round(v, 2) for k, v in flas_kasa.items()},
            "adam_gun": adam_gun,
            "calisilan_gun": calisilan_gun,
            "isci_basina_kasa": round(toplam_kasa / adam_gun, 2) if adam_gun else 0,
            "ort_gunluk_personel": round(adam_gun / calisilan_gun, 1) if calisilan_gun else 0,
            "gun_kasa": gun_kasa,              # {tarih: kasa} — trend + rekor
            "gun_personel": gun_personel,      # {tarih: kişi} — dalgalanma
        }

    def get_hasatci_detay(self, hasatci):
        """Tek bir hasatçının tüm detayı — kişisel dashboard için.
        Döndürür: günlük kayıtlar, flaş kırılımı, oda dağılımı, aylık trend."""
        # Tüm kayıtları flaş bilgisiyle çek (tarti_detay'dan join)
        rows = self.conn.execute("""
            SELECT hk.tarih, hk.oda, hk.kasa, COALESCE(td.flas, 1) AS flas, COALESCE(td.tur, 0) AS tur
            FROM hasatci_kasa hk
            LEFT JOIN tarti_detay td ON td.oda = hk.oda AND td.tarih = hk.tarih
            WHERE hk.hasatci = ? AND hk.kasa > 0
            ORDER BY hk.tarih, hk.oda
        """, (hasatci,)).fetchall()

        gunluk = []           # [(tarih, oda, kasa, flas, tur), ...]
        toplam_kasa = 0
        gunler = set()
        oda_gun = set()
        flas1_kasa = flas2_kasa = 0
        flas1_n = flas2_n = 0
        oda_dagilim = {}      # oda → {kez, kasa}
        aylik = {}            # 'YYYY-MM' → {gun:set, kasa, oda_gun}

        for tarih, oda, kasa, flas, tur in rows:
            gunluk.append((tarih, oda, kasa, flas, tur))
            toplam_kasa += kasa
            gunler.add(tarih)
            oda_gun.add((oda, tarih))
            if flas == 2:
                flas2_kasa += kasa; flas2_n += 1
            else:
                flas1_kasa += kasa; flas1_n += 1
            # Oda dağılımı
            if oda not in oda_dagilim:
                oda_dagilim[oda] = {"kez": 0, "kasa": 0}
            oda_dagilim[oda]["kez"] += 1
            oda_dagilim[oda]["kasa"] += kasa
            # Aylık
            ym = tarih[:7]  # YYYY-MM
            if ym not in aylik:
                aylik[ym] = {"gunler": set(), "kasa": 0, "oda_gun": 0}
            aylik[ym]["gunler"].add(tarih)
            aylik[ym]["kasa"] += kasa
            aylik[ym]["oda_gun"] += 1

        # Yuvarlamalar
        for o in oda_dagilim:
            oda_dagilim[o]["kasa"] = round(oda_dagilim[o]["kasa"], 2)
        aylik_liste = []
        for ym in sorted(aylik):
            aylik_liste.append({
                "ay": ym,
                "gun": len(aylik[ym]["gunler"]),
                "kasa": round(aylik[ym]["kasa"], 2),
                "oda_gun": aylik[ym]["oda_gun"],
            })

        # GÜN BAZLI ÖZET — her gün: bu kişinin o günkü toplamı + o günün genel ortalaması
        gun_bazli = {}  # tarih → {kisi_kasa, odalar:[(oda,kasa,flas),...]}
        for tarih, oda, kasa, flas, tur in gunluk:
            if tarih not in gun_bazli:
                gun_bazli[tarih] = {"kisi_kasa": 0, "odalar": []}
            gun_bazli[tarih]["kisi_kasa"] += kasa
            gun_bazli[tarih]["odalar"].append((oda, kasa, flas))
        gun_ozet = []
        for tarih in sorted(gun_bazli):
            gb = gun_bazli[tarih]
            # O günün genel ortalaması: günün GERÇEK toplam kasası (ozet.toplam_kasa —
            # ana90+kestane+duble+dökme, save_day/recalc_ozet_toplam ile senkron
            # tutulur) ÷ benzersiz kişi. hasat.kasa (ana90-only) kullanmak, kırılımlı
            # günlerde "Gün ort" değerini düşük gösterip herkesin sapmasını şişirirdi.
            oz_row = self.conn.execute(
                "SELECT toplam_kasa FROM ozet WHERE tarih=?", (tarih,)).fetchone()
            gun_toplam = (oz_row[0] if oz_row else 0) or 0
            kisiler = set()
            for (hh,) in self.conn.execute(
                    "SELECT DISTINCT hasatci FROM hasatci_kasa WHERE tarih=? AND kasa>0",
                    (tarih,)).fetchall():
                kisiler.add(hh)
            gun_ort = round(gun_toplam / len(kisiler), 2) if kisiler else 0
            gun_ozet.append({
                "tarih": tarih,
                "kisi_kasa": round(gb["kisi_kasa"], 2),   # bu kişinin o günkü toplamı
                "odalar": gb["odalar"],                     # [(oda, kasa, flas), ...]
                "gun_ortalama": gun_ort,                    # o günün genel ortalaması
                "fark": round(gb["kisi_kasa"] - gun_ort, 2),  # ortalamadan sapma
            })

        return {
            "gunluk": gunluk,
            "gun_ozet": gun_ozet,
            "toplam_kasa": round(toplam_kasa, 2),
            "gun_sayisi": len(gunler),
            "oda_gun": len(oda_gun),
            "flas1_kasa": round(flas1_kasa, 2),
            "flas2_kasa": round(flas2_kasa, 2),
            "flas1_n": flas1_n,
            "flas2_n": flas2_n,
            "oda_dagilim": oda_dagilim,
            "aylik": aylik_liste,
            "kasa_gun": round(toplam_kasa / len(gunler), 2) if gunler else 0,
        }

    def get_hasatci_performans(self, baslangic=None, bitis=None):
        """Tüm hasatçıların performansı: {hasatci: {toplam_kasa, gun_sayisi,
        oda_sayisi (benzersiz), oda_gun (oda-gün katılımı)}}"""
        q = "SELECT hasatci, kasa, tarih, oda FROM hasatci_kasa WHERE kasa>0"
        params = []
        if baslangic:
            q += " AND tarih>=?"; params.append(baslangic)
        if bitis:
            q += " AND tarih<=?"; params.append(bitis)
        rows = self.conn.execute(q, params).fetchall()
        perf = {}
        for hasatci, kasa, tarih, oda in rows:
            if hasatci not in perf:
                perf[hasatci] = {"toplam_kasa": 0, "gunler": set(),
                                 "odalar": set(), "oda_gun": set()}
            perf[hasatci]["toplam_kasa"] += kasa
            perf[hasatci]["gunler"].add(tarih)
            perf[hasatci]["odalar"].add(oda)
            # oda-gün: aynı oda farklı günde tekrar sayılır (B-4 Pzt + B-4 Salı = 2)
            perf[hasatci]["oda_gun"].add((oda, tarih))
        # set'leri sayıya çevir
        sonuc = {}
        for h, d in perf.items():
            gun = len(d["gunler"])
            sonuc[h] = {
                "toplam_kasa": round(d["toplam_kasa"], 2),
                "gun_sayisi": gun,
                "oda_sayisi": len(d["odalar"]),       # benzersiz oda
                "oda_gun": len(d["oda_gun"]),          # oda-gün katılımı (tekrarlı)
                "kasa_gun": round(d["toplam_kasa"] / gun, 2) if gun else 0,
            }
        return sonuc

    def get_oda_hasatci_dokumu(self, oda, tur=None):
        """Bir odada (opsiyonel tur) çalışan hasatçıların FLAŞ BAZLI dökümü.
        Döndürür: {hasatci: {gun_sayisi, toplam_kasa, flas1_kasa, flas2_kasa,
                             flas1_gun, flas2_gun, tarihler:[...]}}"""
        # Bu odanın günlerini + flaşlarını al
        if tur is not None:
            gunler = self.conn.execute(
                "SELECT tarih, flas FROM tarti_detay WHERE oda=? AND tur=?", (oda, tur)).fetchall()
        else:
            gunler = self.conn.execute(
                "SELECT tarih, flas FROM tarti_detay WHERE oda=?", (oda,)).fetchall()
        gun_flas = {t: f for t, f in gunler}  # tarih → flaş
        rows = self.conn.execute(
            "SELECT hasatci, tarih, kasa FROM hasatci_kasa WHERE oda=? AND kasa>0 ORDER BY tarih",
            (oda,)).fetchall()
        dokum = {}
        for hasatci, tarih, kasa in rows:
            if tur is not None and tarih not in gun_flas:
                continue
            flas = gun_flas.get(tarih, 1)
            if hasatci not in dokum:
                dokum[hasatci] = {"gun_sayisi": 0, "toplam_kasa": 0,
                                  "flas1_kasa": 0, "flas2_kasa": 0,
                                  "flas1_gun": 0, "flas2_gun": 0, "tarihler": []}
            dokum[hasatci]["gun_sayisi"] += 1
            dokum[hasatci]["toplam_kasa"] += kasa
            dokum[hasatci]["tarihler"].append(tarih)
            if flas == 2:
                dokum[hasatci]["flas2_kasa"] += kasa
                dokum[hasatci]["flas2_gun"] += 1
            else:
                dokum[hasatci]["flas1_kasa"] += kasa
                dokum[hasatci]["flas1_gun"] += 1
        for h in dokum:
            for k in ("toplam_kasa", "flas1_kasa", "flas2_kasa"):
                dokum[h][k] = round(dokum[h][k], 2)
        return dokum

    def get_hasatci_ozet(self, oda, tur):
        """Bir oda+turun tüm günlerindeki hasatçı kasalarını topla → {hasatci: toplam_kasa, gun_sayisi}"""
        # Bu turun günlerini bul
        gunler = self.conn.execute(
            "SELECT tarih FROM tarti_detay WHERE oda=? AND tur=?", (oda, tur)).fetchall()
        gun_set = {g[0] for g in gunler}
        ozet = {}
        gun_say = {}
        for tarih in gun_set:
            for h, k in self.get_hasatci_kasa(oda, tarih).items():
                ozet[h] = ozet.get(h, 0) + k
                gun_say[h] = gun_say.get(h, 0) + 1
        return ozet, gun_say

    def get_kompost_detay(self, oda, tur):
        r = self.conn.execute(
            "SELECT firma, gelis_tarihi, tonaj, alan_m2, tur_bitti FROM kompost_detay WHERE oda=? AND tur=?",
            (oda, tur)).fetchone()
        if r:
            return {"firma": r[0], "gelis": r[1], "tonaj": r[2], "alan": r[3] or 252,
                    "tur_bitti": bool(r[4]) if len(r) > 4 and r[4] is not None else False}
        return {"firma": "", "gelis": "", "tonaj": 0, "alan": 252, "tur_bitti": False}

    def set_kompost_detay(self, oda, tur, firma, gelis, tonaj, alan=252, tur_bitti=None):
        """tur_bitti=None ise mevcut değeri korur (çağıran yerler bu bilgiyi bilmeyebilir)."""
        if tur_bitti is None:
            mevcut = self.get_kompost_detay(oda, tur)
            tur_bitti = mevcut["tur_bitti"]
        self.conn.execute(
            "INSERT OR REPLACE INTO kompost_detay VALUES(?,?,?,?,?,?,?)",
            (oda, tur, firma, gelis, tonaj, alan, 1 if tur_bitti else 0))
        self.conn.commit()

    def set_tur_bitti(self, oda, tur, bitti: bool):
        """Sadece 'Tur Bitti' işaretini günceller, diğer alanlara dokunmaz."""
        mevcut = self.get_kompost_detay(oda, tur)
        self.conn.execute(
            "INSERT OR REPLACE INTO kompost_detay VALUES(?,?,?,?,?,?,?)",
            (oda, tur, mevcut["firma"], mevcut["gelis"], mevcut["tonaj"], mevcut["alan"],
             1 if bitti else 0))
        self.conn.commit()

    def get_oda_turlari(self, oda):
        """Bir odada kayıtlı tüm tur numaralarını döndür (küçükten büyüğe)"""
        rows = self.conn.execute(
            "SELECT DISTINCT tur FROM tarti_detay WHERE oda=? ORDER BY tur",
            (oda,)).fetchall()
        turlar = [r[0] for r in rows]
        # tarti_detay'da olmayan (eski) günler için varsayılan tur 1
        toplam = self.conn.execute(
            "SELECT COUNT(*) FROM hasat WHERE parsel=? AND kasa>0", (oda,)).fetchone()[0]
        kayitli = self.conn.execute(
            "SELECT COUNT(*) FROM tarti_detay WHERE oda=?", (oda,)).fetchone()[0]
        if toplam > kayitli and 1 not in turlar:
            turlar = [1] + turlar
        return turlar if turlar else [1]

    def get_firma_turlari(self, firma):
        """Belirli bir kompost firmasının tüm (oda, tur) kombinasyonları
        (kompost_detay'dan). Hasat eğrisi öğrenilmiş referansı ve firma
        karşılaştırması için kullanılır."""
        rows = self.conn.execute(
            "SELECT oda, tur FROM kompost_detay WHERE firma=? ORDER BY oda, tur",
            (firma,)).fetchall()
        return [(r[0], r[1]) for r in rows]

    def get_tum_firmalar(self):
        """kompost_detay'da adı geçen tüm firmalar (boş olmayan, alfabetik)."""
        rows = self.conn.execute(
            "SELECT DISTINCT firma FROM kompost_detay "
            "WHERE firma IS NOT NULL AND firma!='' ORDER BY firma").fetchall()
        return [r[0] for r in rows]

    def get_tum_oda_turlar(self):
        """Tesisteki TÜM (oda, tur) kombinasyonları (tarti_detay'dan). Tesis
        geneli hasat eğrisi referansı için kullanılır."""
        rows = self.conn.execute(
            "SELECT DISTINCT oda, tur FROM tarti_detay ORDER BY oda, tur").fetchall()
        return [(r[0], r[1]) for r in rows]

    def get_tur_ikinci(self, oda, tur):
        """Bir oda+turun toplam İkinci kalite kasası (tarti_detay)."""
        r = self.conn.execute(
            "SELECT COALESCE(SUM(ikinci),0) FROM tarti_detay WHERE oda=? AND tur=?",
            (oda, tur)).fetchone()
        return r[0] or 0

    def set_tarti_detay(self, oda, tarih, tur, flas, ana90, kestane, duble, dokme, ikinci):
        self.conn.execute(
            "INSERT OR REPLACE INTO tarti_detay VALUES(?,?,?,?,?,?,?,?,?)",
            (oda, tarih, tur, flas, ana90, kestane, duble, dokme, ikinci))
        self.conn.commit()
        # Üretim Takip (web) ile canlı senkron — SADECE bu satırı Firestore'a
        # kuyruğa alır, yerel kaydı ASLA etkilemez/engellemez (bkz. firestore_sync.py).
        # gelis_tarihi de eklenir ki Üretim Takip tarafı, oda/tur eşleşse bile
        # geliş tarihi farklıysa (mühendis hatası ihtimali) uyarı gösterebilsin.
        if HAS_SYNC:
            try:
                kd = self.get_kompost_detay(oda, tur)
                firestore_sync.enqueue_hasat_sync(
                    oda, tarih, tur, flas, ana90, kestane, duble, dokme, ikinci,
                    gelis_tarihi=kd.get("gelis", ""),
                    firma=kd.get("firma", ""), tonaj=kd.get("tonaj", 0))
            except Exception:
                pass  # senkron asla yerel kaydı bozmasın

    def get_tarti_detay(self, oda, tarih):
        r = self.conn.execute(
            "SELECT tur, flas, ana90, kestane, duble, dokme, ikinci FROM tarti_detay WHERE oda=? AND tarih=?",
            (oda, tarih)).fetchone()
        if r:
            return {"tur": r[0], "flas": r[1], "ana90": r[2], "kestane": r[3],
                    "duble": r[4], "dokme": r[5], "ikinci": r[6]}
        return {"tur": 1, "flas": 1, "ana90": 0, "kestane": 0, "duble": 0, "dokme": 0, "ikinci": 0}

    def get_form_detay(self, oda, tarih):
        """Form ek bilgileri (flaş, ikinci, tikler)"""
        r = self.conn.execute(
            "SELECT flas, kasa_ikinci, kok, renk, tat, koku FROM form_detay WHERE oda=? AND tarih=?",
            (oda, tarih)).fetchone()
        if r:
            return {"flas": r[0], "ikinci": r[1], "kok": r[2], "renk": r[3], "tat": r[4], "koku": r[5]}
        return {"flas": 1, "ikinci": 0, "kok": 0, "renk": 0, "tat": 0, "koku": 0}

    def set_form_detay(self, oda, tarih, flas, ikinci, kok, renk, tat, koku):
        self.conn.execute(
            "INSERT OR REPLACE INTO form_detay VALUES(?,?,?,?,?,?,?,?)",
            (oda, tarih, flas, ikinci, kok, renk, tat, koku))
        self.conn.commit()

    def get_monthly(self, y, m):
        s = f"{y}-{m:02d}-01"
        e = f"{y+1}-01-01" if m == 12 else f"{y}-{m+1:02d}-01"
        c = self.conn
        kasa = c.execute("SELECT SUM(toplam_kasa) FROM ozet WHERE tarih>=? AND tarih<?", (s, e)).fetchone()[0] or 0
        prs  = c.execute("SELECT SUM(personel)    FROM ozet WHERE tarih>=? AND tarih<?", (s, e)).fetchone()[0] or 0
        days = c.execute("SELECT COUNT(*)          FROM ozet WHERE tarih>=? AND tarih<? AND toplam_kasa>0", (s, e)).fetchone()[0] or 0
        return {"kasa": kasa, "pdays": prs, "wdays": days,
                "avg_p": prs/days if days else 0,
                "avg_k": kasa/days if days else 0,
                "kgp":   kasa/prs  if prs  else 0}

    # Tarih aralığı parsel bazlı döküm
    def get_range(self, t1, t2):
        rows = self.conn.execute(
            "SELECT parsel, SUM(kasa) FROM hasat WHERE tarih>=? AND tarih<=? GROUP BY parsel ORDER BY parsel",
            (t1, t2)).fetchall()
        return {r[0]: r[1] for r in rows}

    def get_setting(self, k, d=None):
        r = self.conn.execute("SELECT value FROM ayar WHERE key=?", (k,)).fetchone()
        if r:
            try: return json.loads(r[0])
            except (ValueError, json.JSONDecodeError): return r[0]
        return d

    def set_setting(self, k, v):
        self.conn.execute("INSERT OR REPLACE INTO ayar VALUES(?,?)",
                          (k, json.dumps(v, ensure_ascii=False) if isinstance(v,(dict,list)) else str(v)))
        self.conn.commit()

    def import_excel(self, filepath, progress_cb=None):
        try:
            import openpyxl, datetime as dt
        except ImportError:
            return False, "openpyxl kurulu değil.\nTerminale: pip install openpyxl"
        try:
            wb = openpyxl.load_workbook(filepath, data_only=True)
            c = self.conn.cursor()
            imported = 0
            gun_toplam = {}  # tarih → toplam (N+1 önleme)
            total_sheets = len([s for s in wb.sheetnames if any(mn.lower() in s.lower() for mn in MONTHS)])
            done_sheets = 0
            for sname in wb.sheetnames:
                ml = sname.lower().strip()
                m = next((i+1 for i,mn in enumerate(MONTHS) if mn.lower() in ml), 0)
                if not m:
                    continue
                ws = wb[sname]
                # Başlık satırından tarih sütunlarını çıkar
                # Başlık datetime objesi: 2025-11-01 00:00:00
                header = list(ws.iter_rows(min_row=1, max_row=1, values_only=True))[0]
                date_cols = {}  # {col_index: date}
                for ci, val in enumerate(header):
                    if val is None: continue
                    if isinstance(val, (dt.datetime, dt.date)):
                        d = val.date() if isinstance(val, dt.datetime) else val
                        date_cols[ci] = d
                    else:
                        # String tarih denemesi: "2025-11-01" veya "01.11.2025"
                        s = str(val).strip()
                        for fmt_ in ("%Y-%m-%d", "%d.%m.%Y", "%d/%m/%Y"):
                            try:
                                d = dt.datetime.strptime(s[:10], fmt_).date()
                                date_cols[ci] = d
                                break
                            except ValueError: pass
                if not date_cols:
                    continue
                done_sheets += 1
                if progress_cb:
                    progress_cb(int(done_sheets / max(total_sheets, 1) * 100))
                for row in ws.iter_rows(min_row=2, values_only=True):
                    parsel = str(row[0]).strip() if row[0] else ""
                    if not parsel or parsel.upper() in ("TOP.","TOPLAM","TOP","ORTALAMA",""):
                        continue
                    for ci, d in date_cols.items():
                        if ci >= len(row): continue
                        v = row[ci]
                        if v is None: continue
                        try:
                            kasa = float(v)
                        except (ValueError, TypeError):
                            continue  # Sayı olmayan hücre — atla
                        if kasa <= 0: continue
                        t = d.strftime("%Y-%m-%d")
                        c.execute("INSERT OR IGNORE INTO hasat VALUES(?,?,?)", (t, parsel, kasa))
                        gun_toplam[t] = gun_toplam.get(t, 0) + kasa
                        imported += 1
            self.conn.commit()
            # Her günün ozet.toplam_kasa'sını GERÇEK toplamla (Kestane/Duble/Dökme
            # dahil, tüm odalar) senkronla — sadece bu içe aktarmada eklenenlerle
            # değil. recalc_ozet_toplam mevcut ozet.personel'i de korur (eskiden
            # burada personel=0 ile köreltilip mevcut tik/ekstra kaydı siliniyordu).
            for t in gun_toplam:
                self.recalc_ozet_toplam(t)
            return True, f"{imported} kayıt yüklendi."
        except ImportError:
            return False, "openpyxl kurulu değil. Terminale: pip install openpyxl"
        except FileNotFoundError:
            return False, "Excel dosyası bulunamadı."
        except Exception as e:
            return False, f"Excel okunamadı: {type(e).__name__} — {e}"

# ─── YARDIMCI ────────────────────────────────────────────────────────────────
def fmt(n, d=2):
    try:
        s = f"{float(n):,.{d}f}".replace(",","X").replace(".",",").replace("X",".")
        if "," in s: s = s.rstrip("0").rstrip(",")
        return s
    except (ValueError, TypeError): return "0"

def parse_num(v):
    try:
        s = str(v).strip()
        if "," in s and "." in s:
            # "1.234,56" → binlik nokta, ondalık virgül
            s = s.replace(".", "").replace(",", ".")
        elif "," in s:
            # "45,5" → ondalık virgül
            s = s.replace(",", ".")
        elif "." in s:
            parts = s.split(".")
            # "1.800" → son parça 3 hane → binlik nokta
            # "45.5"  → son parça 1-2 hane → ondalık nokta
            if len(parts) == 2 and len(parts[1]) == 3 and parts[1].isdigit():
                s = s.replace(".", "")  # binlik ayraç
            # else: ondalık nokta, olduğu gibi bırak
        return float(s)
    except (ValueError, TypeError): return 0.0

def kisi_basi_performans(kb):
    """Kişi başı kasaya göre performans etiketi ve rengi döndürür.
    Eşikler: 18+ ideal, 20+ iyi, 25+ çok iyi, 30+ dökme/duble ağırlıklı (bilgi).
    Döndürür: (etiket, renk_hex). kb 0 ise boş."""
    if kb <= 0:
        return ("", "#7a7263")
    if kb >= 30:
        return ("dökme/duble ağırlıklı", "#1e5631")   # koyu yeşil, bilgi
    if kb >= 25:
        return ("çok iyi", "#2f6b3f")                  # yeşil
    if kb >= 20:
        return ("iyi", "#5a9367")                       # açık yeşil
    if kb >= 18:
        return ("ideal", "#d68910")                     # turuncu (ideal eşiği)
    return ("ideal altı", "#c0392b")                    # kırmızı (18 altı)


def parse_date(s):
    for fmt_ in ("%d.%m.%Y", "%d/%m/%Y", "%Y-%m-%d", "%d.%m.%y"):
        try: return datetime.datetime.strptime(s.strip(), fmt_).date()
        except ValueError: pass
    return None

