    def _analiz_yorumlar(self, d0, d1, d12):
        """Kural tabanlı yorum motoru — senin şemana uyarlı (flaş 1/2, kasa bazlı).
        Döndürür: [(ikon, metin, çerçeve_rengi), ...]"""
        notlar = []
        YESIL = "#2f6b3f"; KIRMIZI = "#c0392b"; SARI = "#d68910"

        u0, u12 = d0["toplam_kasa"], d12["toplam_kasa"]
        p0, p12 = d0["adam_gun"], d12["adam_gun"]
        v0, v12 = d0["isci_basina_kasa"], d12["isci_basina_kasa"]

        # Geçen yıl verisi varsa iş gücü/üretim yorumları
        if u12 > 0 and p12 > 0:
            uretim_arti = u0 > u12; uretim_eksi = u0 < u12
            personel_arti = p0 > p12; personel_eksi = p0 < p12

            if uretim_arti and personel_eksi:
                notlar.append(("✅", "İş Gücü Optimizasyonu! Personel geçen yıla göre azaldı "
                    "ama üretim arttı. Hasatçıların toplama hızı ve flaş yönetimi üst düzeyde.", YESIL))
            elif uretim_eksi and personel_arti:
                notlar.append(("⚠", "İş Gücü Verim Kaybı: Personel arttı ama üretim düştü. "
                    "Kişi başı kasa veriminde kayıp var. Flaş zamanlaması ve toplama performansını gözden geçirin.", KIRMIZI))
            elif uretim_arti and personel_arti:
                if v0 > v12:
                    notlar.append(("✅", "Dengeli Büyüme: Ekip de üretim de büyüdü, üstelik kişi başı verim "
                        "de yükseldi. Yeni personel adaptasyonu başarılı.", YESIL))
                else:
                    notlar.append(("⚠", "Hacim Büyüyor Ama Verim Düşük: Üretim arttı ama kişi başı verim geriledi. "
                        "Yeni personelin hız/toplama eğitimine ağırlık verin.", SARI))

        # 2. Flaş performansı (geçen yıla göre)
        f2_0 = d0["flas_kasa"].get(2, 0)
        f2_12 = d12["flas_kasa"].get(2, 0)
        if f2_12 > 0:
            deg = (f2_0 - f2_12) / f2_12 * 100
            if deg <= -20:
                notlar.append(("⚠", f"2. Flaş Düşüşü: 2. flaş verimi geçen yıla göre %{abs(deg):.0f} azaldı. "
                    "Kompostun erken kuruması, kuluçka sıcaklığı veya nemlendirme aksaklıkları incelenmeli.", KIRMIZI))

        # 3. Oda alanı verimliliği (oda alanları tanımlıysa)
        oda_alani = self.db.get_setting("oda_alani", {}) if hasattr(self.db, "get_setting") else {}
        if isinstance(oda_alani, dict) and oda_alani:
            oda_verim = {}
            for oda, kasa in d0["oda_kasa"].items():
                alan = oda_alani.get(oda)
                if alan and alan > 0:
                    oda_verim[oda] = (kasa * self.kg) / alan  # kg/m²
            if len(oda_verim) >= 2:
                en_iyi = max(oda_verim, key=oda_verim.get)
                en_kotu = min(oda_verim, key=oda_verim.get)
                import statistics as _st
                ort = _st.mean(oda_verim.values())
                fark = ((oda_verim[en_kotu] - ort) / ort * 100) if ort else 0
                notlar.append(("📈", f"Alan Analizi: En yüksek m² verimi {oda_verim[en_iyi]:.1f} kg/m² ile "
                    f"{en_iyi} odasında. {en_kotu} odası ortalamanın %{abs(fark):.0f} altında — kontrol edilmeli.", YESIL))

        # NOT: "Oda Üretimi en çok/en az" yorumu KALDIRILDI — ay bazlı oda kıyası
        # yanıltıcı (bir oda ay içinde tur değiştirebilir). Tur bazlı analiz aşağıda.

        # 5. Kişi başı performans eşiği (18 ideal / 20 iyi / 25 çok iyi / 30+ dökme-duble)
        if d0["adam_gun"] > 0:
            if v0 >= 30:
                notlar.append(("ℹ", f"Kişi başı {fmt(v0)} kasa — 30 üstü. Bu seviyede üretim "
                    "genelde dökme ve duble ağırlıklı gider (bilgi).", "#1e5631"))
            elif v0 >= 25:
                notlar.append(("✅", f"Kişi başı {fmt(v0)} kasa — çok iyi performans! "
                    "Hasat disiplini üst düzeyde.", YESIL))
            elif v0 >= 20:
                notlar.append(("✅", f"Kişi başı {fmt(v0)} kasa — iyi performans.", "#5a9367"))
            elif v0 >= 18:
                notlar.append(("🎯", f"Kişi başı {fmt(v0)} kasa — ideal seviyede.", SARI))
            else:
                notlar.append(("⚠", f"Kişi başı {fmt(v0)} kasa — ideal eşiğin (18) altında. "
                    "Odalardaki mantar yoğunluğu veya iş gücü dağılımı kontrol edilebilir.", KIRMIZI))

        # ── YENİ: AY İÇİ TREND (ilk yarı vs ikinci yarı) ──
        gun_kasa = d0.get("gun_kasa", {})
        if len(gun_kasa) >= 6:
            tarihler = sorted(gun_kasa.keys())
            orta = len(tarihler) // 2
            ilk_yari = [gun_kasa[t] for t in tarihler[:orta]]
            ikinci_yari = [gun_kasa[t] for t in tarihler[orta:]]
            if ilk_yari and ikinci_yari:
                ort1 = sum(ilk_yari) / len(ilk_yari)
                ort2 = sum(ikinci_yari) / len(ikinci_yari)
                if ort1 > 0:
                    deg = (ort2 - ort1) / ort1 * 100
                    if deg <= -20:
                        notlar.append(("📉", f"Ay İçi Düşüş: İlk yarı günlük ort. {fmt(ort1)} kasa, "
                            f"ikinci yarı {fmt(ort2)} kasa (%{abs(deg):.0f} düşüş). "
                            "Flaş 2'ye geçiş veya tur sonu olabilir — normal seyir ya da kontrol gerekebilir.", SARI))
                    elif deg >= 20:
                        notlar.append(("📈", f"Ay İçi Yükseliş: İlk yarı günlük ort. {fmt(ort1)} kasa, "
                            f"ikinci yarı {fmt(ort2)} kasa (%{deg:.0f} artış). Üretim ivme kazanıyor.", YESIL))

        # ── YENİ: REKOR GÜN (en yüksek / en düşük) ──
        if gun_kasa:
            en_yuksek_t = max(gun_kasa, key=gun_kasa.get)
            en_dusuk_t = min(gun_kasa, key=gun_kasa.get)
            try:
                ey = datetime.datetime.strptime(en_yuksek_t, "%Y-%m-%d").strftime("%d.%m")
                ed = datetime.datetime.strptime(en_dusuk_t, "%Y-%m-%d").strftime("%d.%m")
            except ValueError:
                ey, ed = en_yuksek_t, en_dusuk_t
            notlar.append(("🏆", f"Rekor Gün: En yüksek {ey} ({fmt(gun_kasa[en_yuksek_t])} kasa), "
                f"en düşük {ed} ({fmt(gun_kasa[en_dusuk_t])} kasa).", YESIL))

        # NOT: "Sürekli Düşük/Yükselen Oda" (ay bazlı) yorumu KALDIRILDI.
        # Bir oda ay içinde tur değiştirebileceği için aylık oda kıyası yanıltıcı.
        # Doğru oda performansı tur bazlı verim bölümünde (aşağıda) gösterilir.

        # ── YENİ: FLAŞ DENGESİ ──
        f1 = d0["flas_kasa"].get(1, 0); f2 = d0["flas_kasa"].get(2, 0)
        toplam_f = f1 + f2
        if toplam_f > 0:
            f1y = f1 / toplam_f * 100
            f2y = f2 / toplam_f * 100
            if f2y < 25:
                notlar.append(("ℹ", f"Flaş Dengesi: 1. flaş %{f1y:.0f}, 2. flaş %{f2y:.0f}. "
                    "2. flaş düşük — erken kesim veya kısa 2. flaş dönemi olabilir.", SARI))
            elif f2y > 50:
                notlar.append(("ℹ", f"Flaş Dengesi: 2. flaş %{f2y:.0f} ile beklenenden yüksek. "
                    "Uzun 2. flaş dönemi veya yoğun ikinci dalga.", SARI))
            else:
                notlar.append(("✅", f"Flaş Dengesi: 1. flaş %{f1y:.0f}, 2. flaş %{f2y:.0f} — dengeli dağılım.", YESIL))

        # ── YENİ: PERSONEL DALGALANMASI ──
        gun_personel = d0.get("gun_personel", {})
        if len(gun_personel) >= 4:
            sayilar = list(gun_personel.values())
            en_az = min(sayilar); en_cok = max(sayilar)
            if en_az > 0 and en_cok >= en_az * 2:
                notlar.append(("⚠", f"Personel Dalgalanması: Günlük kişi sayısı {en_az} ile {en_cok} arası değişti. "
                    "İş gücü planlamasında istikrarsızlık var — bazı günler az kişiyle çok iş riski.", SARI))

        # ── YENİ: HEDEF VERİM KARŞILAŞTIRMASI (hedef tanımlıysa) ──
        hedef = None
        try:
            hedef = self.db.get_setting("hedef_kisi_basi", None)
            hedef = float(hedef) if hedef else None
        except (ValueError, TypeError):
            hedef = None
        if hedef and hedef > 0 and v0 > 0:
            fark = (v0 - hedef) / hedef * 100
            if v0 >= hedef:
                notlar.append(("🎯", f"Hedef Tutturuldu: Kişi başı {fmt(v0)} kasa, hedef {fmt(hedef)} kasa "
                    f"(%{fark:.0f} üzerinde). Tebrikler!", YESIL))
            else:
                notlar.append(("🎯", f"Hedefin Altında: Kişi başı {fmt(v0)} kasa, hedef {fmt(hedef)} kasa "
                    f"(%{abs(fark):.0f} altında). Hedefe ulaşmak için verim artırılmalı.", SARI))

        if not notlar:
            notlar.append(("ℹ", "Bu dönem için belirgin bir sapma tespit edilmedi. Üretim normal seyrediyor.", "#7a7263"))
        return notlar

    def _build_perf(self):
        """Performans sekmesi — scroll'lu kapsayıcı, içerik _perf_refresh ile dolar"""
        ttk.Label(self.t_perf, text="👷 Hasatçı Performansı", style="PH.TLabel").pack(anchor="w", padx=12, pady=(10,2))
        ttk.Label(self.t_perf, text="Eşit dağıtım varsayımıyla · Bir isme tıklayın → kişisel detay dashboard'u açılır",
                  style="S.TLabel").pack(anchor="w", padx=12, pady=(0,6))
        self._perf_inner = self._scroll_frame(self.t_perf, bg=self.C["P"])
        self._perf_refresh()

    def _perf_refresh(self):
        """Performans tablosunu DB'den tazele"""
        if not hasattr(self, "_perf_inner"):
            return
        for w in self._perf_inner.winfo_children():
            w.destroy()
        perf = self.db.get_hasatci_performans()
        if not perf:
            tk.Label(self._perf_inner, text="Henüz hasatçı verisi yok.\n"
                     "Tartı Girişi'nde hasatçı işaretleyip kaydedin.",
                     bg=self.C["P"], fg="#7a7263", font=("Segoe UI",11),
                     justify="center").pack(pady=40)
            return
        # Başlık
        hf = tk.Frame(self._perf_inner, bg="#2f6b3f"); hf.pack(fill="x", padx=4, pady=(4,0))
        for txt, w in [("Hasatçı",16),("Toplam Kasa",12),("Gün",6),("Oda",6),("Kasa/Gün",10)]:
            tk.Label(hf, text=txt, bg="#2f6b3f", fg="white", font=("Segoe UI",9,"bold"),
                     width=w, anchor="w").pack(side="left", padx=2, pady=4)
        # Satırlar (kasa/gün'e göre sıralı — en verimli üstte)
        sirali = sorted(perf.items(), key=lambda x: -x[1]["kasa_gun"])
        for i, (h, d) in enumerate(sirali):
            bg = "#fffdf7" if i%2==0 else "#f3efe2"
            pasif = h in self.pasif_hasatcilar
            row = tk.Frame(self._perf_inner, bg=bg, cursor="hand2"); row.pack(fill="x", padx=4)
            ad_txt = f"{h} (pasif)" if pasif else h
            etiketler = []
            etiketler.append(tk.Label(row, text=ad_txt, bg=bg, fg="#999" if pasif else self.C["G"],
                     font=("Segoe UI",9,"bold","underline"), width=16, anchor="w"))
            etiketler[-1].pack(side="left", padx=2, pady=3)
            etiketler.append(tk.Label(row, text=fmt(d["toplam_kasa"]), bg=bg, fg=self.C["G"],
                     font=("Segoe UI",9,"bold"), width=12, anchor="w")); etiketler[-1].pack(side="left", padx=2)
            etiketler.append(tk.Label(row, text=str(d["gun_sayisi"]), bg=bg, fg=self.C["I"],
                     font=("Segoe UI",9), width=6, anchor="w")); etiketler[-1].pack(side="left", padx=2)
            etiketler.append(tk.Label(row, text=str(d["oda_gun"]), bg=bg, fg=self.C["I"],
                     font=("Segoe UI",9), width=6, anchor="w")); etiketler[-1].pack(side="left", padx=2)
            etiketler.append(tk.Label(row, text=fmt(d["kasa_gun"]), bg=bg, fg="#d68910",
                     font=("Segoe UI",9,"bold"), width=10, anchor="w")); etiketler[-1].pack(side="left", padx=2)
            def ac(e, ad=h): self._hasatci_dashboard(ad)
            row.bind("<Button-1>", ac)
            for et in etiketler:
                et.configure(cursor="hand2"); et.bind("<Button-1>", ac)

    def _hasatci_performans_ekran(self):
        """Eski popup — artık Performans sekmesine yönlendirir"""
        try:
            tabs = [self._nb.tab(i,"text").strip() for i in range(self._nb.index("end"))]
            for i, t in enumerate(tabs):
                if "Performans" in t:
                    self._nb.select(i); return
        except Exception:
            pass

    def _hasatci_dashboard(self, hasatci):
        """Tek hasatçının kişisel detay paneli — günlük, flaş, oda, aylık."""
        d = self.db.get_hasatci_detay(hasatci)
        dlg = tk.Toplevel(self); dlg.title(f"{hasatci} — Detay")
        dlg.geometry("640x620"); dlg.grab_set(); dlg.configure(bg=self.C["B"])

        # Başlık
        pasif = hasatci in self.pasif_hasatcilar
        bas = f"👷 {hasatci}" + (" (pasif)" if pasif else "")
        tk.Label(dlg, text=bas, bg=self.C["B"], fg=self.C["G"],
                 font=("Georgia",15,"bold")).pack(pady=(12,2))
        tk.Label(dlg, text="Tüm kasa rakamları eşit dağıtım tahminidir — gerçek bireysel sayı değildir",
                 bg=self.C["B"], fg="#b08", font=("Segoe UI",8)).pack(pady=(0,8))

        if not d["gunluk"]:
            tk.Label(dlg, text="Bu hasatçı için kayıt yok.", bg=self.C["B"],
                     fg="#7a7263", font=("Segoe UI",11)).pack(pady=40)
            ttk.Button(dlg, text="Kapat", command=dlg.destroy).pack(pady=10)
            return

        # Özet kartlar
        kf = tk.Frame(dlg, bg=self.C["B"]); kf.pack(fill="x", padx=12, pady=4)
        kartlar = [
            ("Toplam Kasa", fmt(d["toplam_kasa"]), self.C["G"]),
            ("Çalıştığı Gün", str(d["gun_sayisi"]), self.C["I"]),
            ("Oda-Gün", str(d["oda_gun"]), self.C["I"]),
            ("Kasa/Gün", fmt(d["kasa_gun"]), "#d68910"),
        ]
        for lb, vl, renk in kartlar:
            c = tk.Frame(kf, bg=self.C["P"], highlightbackground=self.C["L"], highlightthickness=1)
            c.pack(side="left", expand=True, fill="x", padx=3)
            tk.Label(c, text=lb, bg=self.C["P"], fg="#7a7263", font=("Segoe UI",8)).pack(pady=(6,0))
            tk.Label(c, text=vl, bg=self.C["P"], fg=renk, font=("Segoe UI",14,"bold")).pack(pady=(0,6))

        # Flaş kırılımı (yatay bar)
        ff = tk.Frame(dlg, bg=self.C["B"]); ff.pack(fill="x", padx=12, pady=(10,2))
        tk.Label(ff, text="🌊 Flaş Kırılımı", bg=self.C["B"], fg=self.C["I"],
                 font=("Segoe UI",10,"bold")).pack(anchor="w")
        f1, f2 = d["flas1_kasa"], d["flas2_kasa"]
        tk.Label(ff, text=f"1. Flaş (bol/kolay): {fmt(f1)} kasa · {d['flas1_n']} gün-oda    "
                         f"2. Flaş (seyrek/zor): {fmt(f2)} kasa · {d['flas2_n']} gün-oda",
                 bg=self.C["B"], fg=self.C["G"], font=("Segoe UI",9)).pack(anchor="w", pady=2)

        # Scroll'lu içerik (oda dağılımı + aylık + günlük)
        cer = tk.Frame(dlg, bg=self.C["P"]); cer.pack(fill="both", expand=True, padx=12, pady=6)
        canvas = tk.Canvas(cer, bg=self.C["P"], highlightthickness=0)
        sb = ttk.Scrollbar(cer, orient="vertical", command=canvas.yview)
        inner = tk.Frame(canvas, bg=self.C["P"])
        inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.create_window((0,0), window=inner, anchor="nw")
        canvas.configure(yscrollcommand=sb.set)
        canvas.pack(side="left", fill="both", expand=True); sb.pack(side="right", fill="y")

        # Oda dağılımı
        tk.Label(inner, text="🏠 Oda Dağılımı (en çok nerede çalıştı)", bg=self.C["P"],
                 fg=self.C["I"], font=("Segoe UI",10,"bold")).pack(anchor="w", padx=6, pady=(6,2))
        oda_sirali = sorted(d["oda_dagilim"].items(), key=lambda x: -x[1]["kez"])
        for oda, od in oda_sirali:
            tk.Label(inner, text=f"  {oda}: {od['kez']} kez · {fmt(od['kasa'])} kasa",
                     bg=self.C["P"], fg=self.C["G"], font=("Segoe UI",9)).pack(anchor="w", padx=12)

        # Aylık trend
        tk.Label(inner, text="📈 Aylık Devamlılık", bg=self.C["P"],
                 fg=self.C["I"], font=("Segoe UI",10,"bold")).pack(anchor="w", padx=6, pady=(10,2))
        ay_adlari = ["", "Ocak","Şubat","Mart","Nisan","Mayıs","Haziran",
                     "Temmuz","Ağustos","Eylül","Ekim","Kasım","Aralık"]
        for a in d["aylik"]:
            try:
                yil, ay = a["ay"].split("-")
                ay_str = f"{ay_adlari[int(ay)]} {yil}"
            except (ValueError, IndexError):
                ay_str = a["ay"]
            tk.Label(inner, text=f"  {ay_str}: {a['gun']} gün · {a['oda_gun']} oda-gün · {fmt(a['kasa'])} kasa",
                     bg=self.C["P"], fg=self.C["G"], font=("Segoe UI",9)).pack(anchor="w", padx=12)

        # Günlük tablo
        tk.Label(inner, text="📅 Günlük Kayıtlar (gün toplamı + o günün genel ortalaması)", bg=self.C["P"],
                 fg=self.C["I"], font=("Segoe UI",10,"bold")).pack(anchor="w", padx=6, pady=(10,2))
        for gi, gun in enumerate(d["gun_ozet"]):
            try:
                tg = datetime.datetime.strptime(gun["tarih"], "%Y-%m-%d").strftime("%d.%m.%Y")
            except ValueError:
                tg = gun["tarih"]
            # Gün başlığı: tarih + bu kişinin toplamı + genel ortalama + fark
            fark = gun["fark"]
            if fark > 0.5:
                fark_txt = f"▲ ort.+{fmt(fark)}"; fark_renk = self.C["G"]
            elif fark < -0.5:
                fark_txt = f"▼ ort.{fmt(fark)}"; fark_renk = "#c0392b"
            else:
                fark_txt = "≈ ortalama"; fark_renk = "#7a7263"
            gbas = tk.Frame(inner, bg="#e8e0cf"); gbas.pack(fill="x", padx=6, pady=(6,0))
            tk.Label(gbas, text=f"📆 {tg}", bg="#e8e0cf", fg=self.C["I"],
                     font=("Segoe UI",9,"bold"), width=12, anchor="w").pack(side="left", padx=2, pady=2)
            tk.Label(gbas, text=f"Bu kişi: {fmt(gun['kisi_kasa'])} kasa", bg="#e8e0cf", fg="#d68910",
                     font=("Segoe UI",9,"bold")).pack(side="left", padx=6)
            tk.Label(gbas, text=f"Gün ort: {fmt(gun['gun_ortalama'])}", bg="#e8e0cf", fg=self.C["I"],
                     font=("Segoe UI",9)).pack(side="left", padx=6)
            tk.Label(gbas, text=fark_txt, bg="#e8e0cf", fg=fark_renk,
                     font=("Segoe UI",9,"bold")).pack(side="left", padx=6)
            # Oda kırılımı (alt satırlar)
            for oda, kasa, flas in gun["odalar"]:
                r = tk.Frame(inner, bg="#fffdf7"); r.pack(fill="x", padx=6)
                tk.Label(r, text="", bg="#fffdf7", width=3).pack(side="left")
                tk.Label(r, text=f"↳ {oda}", bg="#fffdf7", fg=self.C["I"], font=("Segoe UI",8,"bold"),
                         width=10, anchor="w").pack(side="left", padx=1)
                tk.Label(r, text=f"{fmt(kasa)} kasa", bg="#fffdf7", fg="#d68910", font=("Segoe UI",8),
                         width=12, anchor="w").pack(side="left", padx=1)
                tk.Label(r, text=f"{flas}.flaş", bg="#fffdf7", fg=self.C["G"], font=("Segoe UI",8),
                         width=8, anchor="w").pack(side="left", padx=1)

        ttk.Button(dlg, text="Kapat", command=dlg.destroy).pack(pady=8)

    def _refresh_firma_list(self):
        for w in self._firma_listbox_frame.winfo_children():
            w.destroy()
        self._firma_listbox = tk.Listbox(self._firma_listbox_frame, height=4,
                                         font=("Segoe UI",10), selectmode="single")
        for fr in self.firmalar:
            self._firma_listbox.insert("end", fr)
        self._firma_listbox.pack(fill="x")

    def _firma_ekle(self):
        ad = self._yeni_firma_var.get().strip()
        if not ad:
            messagebox.showwarning("Uyarı", "Firma adı girin."); return
        if ad in self.firmalar:
            messagebox.showinfo("Bilgi", "Bu firma zaten var."); return
        self.firmalar.append(ad)
        self.db.set_setting("firmalar", self.firmalar)
        self._yeni_firma_var.set("")
        self._refresh_firma_list()
        if hasattr(self, "_form_firma_cb"):
            self._form_firma_cb["values"] = self.firmalar
        messagebox.showinfo("Eklendi", f"'{ad}' firması eklendi.")

    def _firma_sil(self):
        sec = self._firma_listbox.curselection()
        if not sec:
            messagebox.showwarning("Uyarı", "Silinecek firmayı seçin."); return
        ad = self._firma_listbox.get(sec[0])
        if not messagebox.askyesno("Onay", f"'{ad}' firması silinsin mi?"):
            return
        self.firmalar.remove(ad)
        self.db.set_setting("firmalar", self.firmalar)
        self._refresh_firma_list()
        if hasattr(self, "_form_firma_cb"):
            self._form_firma_cb["values"] = self.firmalar
        messagebox.showinfo("Silindi", f"'{ad}' firması silindi.")

    def _oda_ekle(self):
        yeni = self._yeni_oda_var.get().strip().upper()
        if not yeni:
            messagebox.showwarning("Uyarı", "Oda adı boş olamaz."); return
        if yeni in self.plots:
            messagebox.showwarning("Uyarı", f"'{yeni}' zaten mevcut."); return
        self.plots.append(yeni)
        self.db.set_setting("plots", self.plots)
        self._yeni_oda_var.set("")
        self._refresh_oda_list()
        # Günlük giriş ve tartı sekmelerini güncelle
        self._gd_refresh()
        messagebox.showinfo("Eklendi", f"'{yeni}' odası eklendi.")

    def _oda_sil(self):
        sel = self._oda_lb.curselection()
        if not sel:
            messagebox.showwarning("Uyarı", "Silmek için bir oda seçin."); return
        oda = self._oda_lb.get(sel[0])
        if not messagebox.askyesno("Emin misiniz?",
                f"'{oda}' odası listeden kaldırılacak.\n"
                f"Mevcut hasat verileri silinmez, sadece giriş listesinden çıkar."):
            return
        self.plots.remove(oda)
        self.db.set_setting("plots", self.plots)
        self._refresh_oda_list()
        self._gd_refresh()
        messagebox.showinfo("Silindi", f"'{oda}' listeden kaldırıldı.")

    def _oda_adlandir(self):
        sel = self._oda_lb.curselection()
        if not sel:
            messagebox.showwarning("Uyarı", "Yeniden adlandırmak için bir oda seçin."); return
        eski = self._oda_lb.get(sel[0])
        # Yeni ad için dialog
        dlg = tk.Toplevel(self)
        dlg.title("Odayı Yeniden Adlandır")
        dlg.geometry("340x160"); dlg.resizable(False, False); dlg.grab_set()
        dlg.configure(bg=self.C["B"])
        tk.Label(dlg, text=f"Oda: {eski}", bg=self.C["B"], fg=self.C["G"],
                 font=("Georgia",12,"bold")).pack(pady=(16,4))
        tk.Label(dlg, text="Yeni ad:", bg=self.C["B"], fg=self.C["I"],
                 font=("Segoe UI",10)).pack()
        yeni_var = tk.StringVar(value=eski)
        e = tk.Entry(dlg, textvariable=yeni_var, width=16, font=("Segoe UI",11), justify="center")
        e.pack(pady=6); e.select_range(0, "end"); e.focus()
        result = [None]
        def tamam():
            result[0] = yeni_var.get().strip().upper()
            dlg.destroy()
        e.bind("<Return>", lambda ev: tamam())
        btn_f = tk.Frame(dlg, bg=self.C["B"]); btn_f.pack(pady=8)
        ttk.Button(btn_f, text="Tamam", style="Gr.TButton", command=tamam).pack(side="left", padx=6)
        ttk.Button(btn_f, text="İptal", command=dlg.destroy).pack(side="left", padx=6)
        self.wait_window(dlg)
        if not result[0] or result[0] == eski: return
        yeni = result[0]
        if yeni in self.plots:
            messagebox.showwarning("Uyarı", f"'{yeni}' adı zaten mevcut."); return
        # Oda listesinde güncelle
        idx = self.plots.index(eski)
        self.plots[idx] = yeni
        self.db.set_setting("plots", self.plots)
        # DB'deki hasat verilerini güncelle (5 tablonun TÜMÜ — oda adı bunların
        # hepsinde anahtar sütun; sadece 'hasat' güncellenirse diğer 4 tablodaki
        # kırılım/hasatçı/form/kompost verisi eski isimde yetim kalır)
        self.db.conn.execute("UPDATE hasat SET parsel=? WHERE parsel=?", (yeni, eski))
        self.db.conn.execute("UPDATE tarti_detay SET oda=? WHERE oda=?", (yeni, eski))
        self.db.conn.execute("UPDATE form_detay SET oda=? WHERE oda=?", (yeni, eski))
        self.db.conn.execute("UPDATE hasatci_kasa SET oda=? WHERE oda=?", (yeni, eski))
        self.db.conn.execute("UPDATE kompost_detay SET oda=? WHERE oda=?", (yeni, eski))
        self.db.conn.commit()
        self._refresh_oda_list()
        self._gd_refresh()
        messagebox.showinfo("Yeniden Adlandırıldı",
            f"'{eski}' → '{yeni}'\n\nTüm geçmiş veriler yeni ad altında görünecek.")

