    # PDF ÇIKTILARI
    # ══════════════════════════════════════════════════════════════════════
    def _pdf_hazirla(self):
        """reportlab kontrolü + Türkçe font (normal/bold/italic). Başarısızsa False döner."""
        try:
            from reportlab.lib.pagesizes import A4
            from reportlab.lib import colors
            from reportlab.lib.units import cm
            from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            from reportlab.pdfbase import pdfmetrics
            from reportlab.pdfbase.ttfonts import TTFont
        except ImportError:
            return False
        # Türkçe fontları kaydet (normal + bold + italic). Zaten kayıtlıysa atla.
        kayitli = pdfmetrics.getRegisteredFontNames()
        font_setleri = [
            ("TR", ["C:/Windows/Fonts/arial.ttf",
                    "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
                    "/usr/share/fonts/truetype/liberation/LiberationSans-Regular.ttf"]),
            ("TR-Bold", ["C:/Windows/Fonts/arialbd.ttf",
                         "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
                         "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf"]),
            ("TR-Italic", ["C:/Windows/Fonts/ariali.ttf",
                           "/usr/share/fonts/truetype/dejavu/DejaVuSans-Oblique.ttf",
                           "/usr/share/fonts/truetype/liberation/LiberationSans-Italic.ttf"]),
        ]
        for ad, adaylar in font_setleri:
            if ad in kayitli:
                continue
            for yol in adaylar:
                if os.path.exists(yol):
                    try:
                        pdfmetrics.registerFont(TTFont(ad, yol))
                        break
                    except Exception:
                        continue
        return True

    def _font_bul(self):
        """Türkçe karakter destekli bir TTF font bul (Windows/Linux)."""
        from reportlab.pdfbase import pdfmetrics
        from reportlab.pdfbase.ttfonts import TTFont
        adaylar = [
            "C:/Windows/Fonts/arial.ttf",
            "C:/Windows/Fonts/calibri.ttf",
            "C:/Windows/Fonts/tahoma.ttf",
            "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
            "/usr/share/fonts/truetype/liberation/LiberationSans-Regular.ttf",
        ]
        for yol in adaylar:
            if os.path.exists(yol):
                try:
                    pdfmetrics.registerFont(TTFont("TR", yol))
                    return "TR"
                except Exception:
                    continue
        return "Helvetica"  # son çare (Türkçe karakterler bozuk olabilir)

    def _aylik_pdf(self):
        if not self._pdf_hazirla():
            messagebox.showerror("Hata",
                "PDF için reportlab gerekli.\nTerminale: pip install reportlab"); return
        try:
            y = int(self._ay_y.get()); m = MONTHS.index(self._ay_m.get()) + 1
        except ValueError:
            messagebox.showwarning("Uyarı", "Geçerli yıl/ay seçin."); return

        d = self.db.get_monthly(y, m)
        if d["kasa"] == 0:
            messagebox.showwarning("Uyarı", "Bu ayda veri yok."); return

        from tkinter import filedialog
        yol = filedialog.asksaveasfilename(defaultextension=".pdf",
            initialfile=f"Aylik_Ozet_{MONTHS[m-1]}_{y}.pdf",
            filetypes=[("PDF","*.pdf")])
        if not yol: return

        from reportlab.lib.pagesizes import A4
        from reportlab.lib import colors
        from reportlab.lib.units import cm
        from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
        from reportlab.lib.styles import ParagraphStyle
        font = self._font_bul()

        doc = SimpleDocTemplate(yol, pagesize=A4, topMargin=2*cm, bottomMargin=2*cm)
        H1 = ParagraphStyle("H1", fontName=font, fontSize=18, textColor=colors.HexColor("#2f6b3f"), spaceAfter=4)
        H2 = ParagraphStyle("H2", fontName=font, fontSize=11, textColor=colors.HexColor("#7a7263"), spaceAfter=12)
        Nrm = ParagraphStyle("N", fontName=font, fontSize=10)
        ogeler = []
        ogeler.append(Paragraph("Aylık Hasat Özeti", H1))
        ogeler.append(Paragraph(f"{MONTHS[m-1]} {y}", H2))

        kasa_kisi = (d["kasa"]/d["pdays"]) if d["pdays"] > 0 else 0
        veriler = [
            ["Aylık Toplam Kasa", fmt(d["kasa"]) + " kasa"],
            ["Aylık Toplam Kilo", fmt(d["kasa"]*self.kg) + " kg"],
            ["Çalışılan Gün", str(d["wdays"]) + " gün"],
            ["Toplam Kişi (personel-gün)", str(int(d["pdays"])) + " kişi"],
            ["Ortalama Hasatçı/Gün", fmt(d["avg_p"]) + " kişi"],
            ["Ortalama Kasa/Gün", fmt(d["avg_k"]) + " kasa"],
            ["Kişi Başı Ortalama Kasa", fmt(kasa_kisi) + " kasa"],
        ]
        t = Table(veriler, colWidths=[9*cm, 6*cm])
        t.setStyle(TableStyle([
            ("FONTNAME",(0,0),(-1,-1),font),
            ("FONTSIZE",(0,0),(-1,-1),11),
            ("TEXTCOLOR",(0,0),(0,-1),colors.HexColor("#2b2620")),
            ("TEXTCOLOR",(1,0),(1,-1),colors.HexColor("#2f6b3f")),
            ("FONTSIZE",(1,0),(1,-1),12),
            ("ROWBACKGROUNDS",(0,0),(-1,-1),[colors.HexColor("#fffdf7"), colors.HexColor("#f3efe2")]),
            ("GRID",(0,0),(-1,-1),0.5,colors.HexColor("#e2dccb")),
            ("PADDING",(0,0),(-1,-1),8),
            ("VALIGN",(0,0),(-1,-1),"MIDDLE"),
        ]))
        ogeler.append(t)
        ogeler.append(Spacer(1, 0.5*cm))

        # Günlük döküm tablosu
        daily = self.db.get_daily_in_month(y, m)
        if daily:
            ogeler.append(Paragraph("Günlük Kasa Dağılımı", H2))
            satirlar = [["Gün", "Kasa", "Kilo"]]
            for gun, kasa in daily:
                satirlar.append([str(gun), fmt(kasa), fmt(kasa*self.kg)])
            t2 = Table(satirlar, colWidths=[3*cm, 4*cm, 4*cm])
            t2.setStyle(TableStyle([
                ("FONTNAME",(0,0),(-1,-1),font),
                ("FONTSIZE",(0,0),(-1,-1),9),
                ("BACKGROUND",(0,0),(-1,0),colors.HexColor("#2f6b3f")),
                ("TEXTCOLOR",(0,0),(-1,0),colors.white),
                ("ROWBACKGROUNDS",(0,1),(-1,-1),[colors.HexColor("#fffdf7"), colors.HexColor("#f3efe2")]),
                ("GRID",(0,0),(-1,-1),0.5,colors.HexColor("#e2dccb")),
                ("ALIGN",(1,0),(-1,-1),"RIGHT"),
                ("PADDING",(0,0),(-1,-1),5),
            ]))
            ogeler.append(t2)

        try:
            doc.build(ogeler)
            messagebox.showinfo("PDF Hazır", f"Kaydedildi:\n{yol}")
            try:
                os.startfile(yol)
            except (AttributeError, OSError):
                pass
        except Exception as e:
            messagebox.showerror("Hata", f"PDF oluşturulamadı: {e}")

    def _yillik_pdf(self):
        if not self._pdf_hazirla():
            messagebox.showerror("Hata",
                "PDF için reportlab gerekli.\nTerminale: pip install reportlab"); return
        try:
            y = int(self._yl_y.get())
        except ValueError:
            messagebox.showwarning("Uyarı", "Geçerli yıl seçin."); return

        from tkinter import filedialog
        yol = filedialog.asksaveasfilename(defaultextension=".pdf",
            initialfile=f"Yillik_Ozet_{y}.pdf", filetypes=[("PDF","*.pdf")])
        if not yol: return

        from reportlab.lib.pagesizes import A4
        from reportlab.lib import colors
        from reportlab.lib.units import cm
        from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
        from reportlab.lib.styles import ParagraphStyle
        font = self._font_bul()

        doc = SimpleDocTemplate(yol, pagesize=A4, topMargin=2*cm, bottomMargin=2*cm)
        H1 = ParagraphStyle("H1", fontName=font, fontSize=18, textColor=colors.HexColor("#2f6b3f"), spaceAfter=4)
        H2 = ParagraphStyle("H2", fontName=font, fontSize=11, textColor=colors.HexColor("#7a7263"), spaceAfter=12)
        ogeler = [Paragraph("Yıllık Hasat Özeti", H1), Paragraph(f"{y} Yılı", H2)]

        satirlar = [["Ay", "Kasa", "Kilo", "Çalışılan Gün", "Toplam Kişi", "Kasa/Kişi"]]
        tK = tG = tP = 0
        for m in range(1, 13):
            dd = self.db.get_monthly(y, m)
            if dd["wdays"] == 0: continue
            kk = (dd["kasa"]/dd["pdays"]) if dd["pdays"]>0 else 0
            satirlar.append([MONTHS[m-1], fmt(dd["kasa"]), fmt(dd["kasa"]*self.kg),
                             str(dd["wdays"]), str(int(dd["pdays"])), fmt(kk)])
            tK += dd["kasa"]; tG += dd["wdays"]; tP += dd["pdays"]
        if tG:
            satirlar.append(["TOPLAM", fmt(tK), fmt(tK*self.kg), str(tG), str(int(tP)),
                             fmt(tK/tP) if tP else "0"])

        t = Table(satirlar, colWidths=[3*cm, 2.6*cm, 2.8*cm, 3*cm, 2.6*cm, 2.4*cm])
        t.setStyle(TableStyle([
            ("FONTNAME",(0,0),(-1,-1),font),
            ("FONTSIZE",(0,0),(-1,-1),9),
            ("BACKGROUND",(0,0),(-1,0),colors.HexColor("#2f6b3f")),
            ("TEXTCOLOR",(0,0),(-1,0),colors.white),
            ("ROWBACKGROUNDS",(0,1),(-1,-2),[colors.HexColor("#fffdf7"), colors.HexColor("#f3efe2")]),
            ("BACKGROUND",(0,-1),(-1,-1),colors.HexColor("#e8e3d8")),
            ("FONTSIZE",(0,-1),(-1,-1),10),
            ("GRID",(0,0),(-1,-1),0.5,colors.HexColor("#e2dccb")),
            ("ALIGN",(1,0),(-1,-1),"RIGHT"),
            ("ALIGN",(0,0),(0,-1),"LEFT"),
            ("PADDING",(0,0),(-1,-1),6),
        ]))
        ogeler.append(t)

        try:
            doc.build(ogeler)
            messagebox.showinfo("PDF Hazır", f"Kaydedildi:\n{yol}")
            try:
                os.startfile(yol)
            except (AttributeError, OSError):
                pass
        except Exception as e:
            messagebox.showerror("Hata", f"PDF oluşturulamadı: {e}")

