    def _otomatik_tur_ekran(self):
        """Her oda için son tur numarası girilen pencere"""
        dlg = tk.Toplevel(self); dlg.title("Otomatik Tur/Flaş Çöz")
        dlg.geometry("440x560"); dlg.grab_set(); dlg.configure(bg=self.C["B"])
        tk.Label(dlg, text="🤖 Otomatik Tur/Flaş Çözme", bg=self.C["B"], fg=self.C["G"],
                 font=("Georgia",14,"bold")).pack(pady=(14,2))
        tk.Label(dlg, text="Her odanın SON (en güncel) tur numarasını girin.\n"
                 "Boş bırakılan odalar atlanır.",
                 bg=self.C["B"], fg=self.C["I"], font=("Segoe UI",9)).pack(pady=(0,8))

        # Kaydırılabilir oda listesi
        cv = tk.Canvas(dlg, bg=self.C["P"], highlightthickness=0, height=380)
        sb = ttk.Scrollbar(dlg, orient="vertical", command=cv.yview)
        cv.configure(yscrollcommand=sb.set)
        sb.pack(side="right", fill="y"); cv.pack(side="top", fill="both", expand=True, padx=12)
        inner = tk.Frame(cv, bg=self.C["P"])
        cv.create_window((0,0), window=inner, anchor="nw")
        inner.bind("<Configure>", lambda e: cv.configure(scrollregion=cv.bbox("all")))
        def _wheel(e):
            cv.yview_scroll(int(-1*(e.delta/120)), "units")
        cv.bind("<Enter>", lambda e: cv.bind_all("<MouseWheel>", _wheel))
        cv.bind("<Leave>", lambda e: cv.unbind_all("<MouseWheel>"))

        # Başlık
        hf = tk.Frame(inner, bg="#e8e3d8"); hf.pack(fill="x")
        tk.Label(hf, text="Oda", width=10, bg="#e8e3d8", fg=self.C["I"],
                 font=("Segoe UI",9,"bold")).pack(side="left", padx=4, pady=4)
        tk.Label(hf, text="Dönem sayısı", width=12, bg="#e8e3d8", fg=self.C["I"],
                 font=("Segoe UI",9,"bold")).pack(side="left", padx=4)
        tk.Label(hf, text="Son Tur No", width=12, bg="#e8e3d8", fg=self.C["I"],
                 font=("Segoe UI",9,"bold")).pack(side="left", padx=4)

        # Her oda için dönem sayısını hesapla + giriş kutusu
        self._oto_vars = {}
        import datetime as _dt
        for oda in self.plots:
            rows = self.db.conn.execute(
                "SELECT tarih FROM hasat WHERE parsel=? AND kasa>0 ORDER BY tarih", (oda,)).fetchall()
            if not rows:
                continue
            gunler = []
            for (t,) in rows:
                try: gunler.append(_dt.datetime.strptime(t,"%Y-%m-%d").date())
                except ValueError: pass
            donem = 1
            for i in range(1, len(gunler)):
                if (gunler[i]-gunler[i-1]).days >= 30:
                    donem += 1
            row = tk.Frame(inner, bg=self.C["P"]); row.pack(fill="x")
            tk.Label(row, text=oda, width=10, bg=self.C["P"], fg=self.C["I"],
                     font=("Segoe UI",10,"bold")).pack(side="left", padx=4, pady=2)
            tk.Label(row, text=f"{donem} dönem", width=12, bg=self.C["P"], fg="#7a7263",
                     font=("Segoe UI",9)).pack(side="left", padx=4)
            v = tk.StringVar()
            tk.Entry(row, textvariable=v, width=10, justify="center",
                     font=("Segoe UI",10), bg="#fffdf7").pack(side="left", padx=4)
            self._oto_vars[oda] = v

        def coz():
            sonuc = []
            for oda, v in self._oto_vars.items():
                s = v.get().strip()
                if not s:
                    continue
                try:
                    son_tur = int(parse_num(s))
                except (ValueError, TypeError):
                    continue
                r = self.db.otomatik_tur_flas(oda, son_tur)
                if r:
                    atanan, donem_say, ilk = r
                    sonuc.append(f"{oda}: Tur {ilk}-{son_tur} ({atanan} gün)")
            dlg.destroy()
            if sonuc:
                messagebox.showinfo("Çözüldü",
                    "Tur/Flaş otomatik atandı:\n\n" + "\n".join(sonuc[:20]) +
                    (f"\n... +{len(sonuc)-20} oda" if len(sonuc)>20 else ""))
                if hasattr(self, "_form_inner"):
                    self._form_oda_secildi()
            else:
                messagebox.showinfo("Bilgi", "Hiçbir odaya tur numarası girilmedi.")

        bf = tk.Frame(dlg, bg=self.C["B"]); bf.pack(pady=10)
        ttk.Button(bf, text="🤖 Çöz ve Ata", style="Gr.TButton", command=coz).pack(side="left", padx=6)
        ttk.Button(bf, text="İptal", command=dlg.destroy).pack(side="left", padx=6)

